function scoreSpriteVariantKey(key, {
    adultMode = false,
    desiredPose = '',
    desiredExpression = '',
    desiredOutfit = '',
    activeSpeaker = false,
    textSignals = null,
} = {}) {
    const parts = String(key || '').split('.');
    const mode = parts[0] || 'base';
    let score = 0;
    if (adultMode && mode === 'adult') score += 100;
    if (!adultMode && mode === 'base') score += 80;
    if (activeSpeaker) score += 8;
    const normalizedKey = parts.map(normalizeSpriteVariantToken).join('.');
    const pose = normalizeSpriteVariantToken(desiredPose);
    const expression = normalizeSpriteVariantToken(desiredExpression);
    const outfit = normalizeSpriteVariantToken(desiredOutfit);
    if (pose && normalizedKey.includes(pose)) score += 18;
    if (expression && normalizedKey.includes(expression)) score += 18;
    if (outfit && normalizedKey.includes(outfit)) score += 12;
    const signalHits = [];
    const signalScore = (items = [], weight = 0, label = '') => items.reduce((total, item) => {
        const token = normalizeSpriteVariantToken(item);
        if (!token || !normalizedKey.includes(token)) {
            return total;
        }
        signalHits.push(`${label}:${token}`);
        return total + weight;
    }, 0);
    score += signalScore(textSignals?.pose || [], 16, 'pose');
    score += signalScore(textSignals?.expression || [], 14, 'expr');
    score += signalScore(textSignals?.outfit || [], 10, 'outfit');
    if (/idle|neutral|default|soft_smile|system_avatar/u.test(normalizedKey)) score += adultMode ? 0 : 4;
    return {
        score,
        signalHits,
    };
}

function resolveCharacterSpriteVariantAsset(profile = {}, {
    state = null,
    storyMode = '',
    segment = null,
    activeSpeakerId = '',
    allowGrokMainStage = false,
    stageText = '',
} = {}) {
    const { id, variants } = spriteVariantEntriesForProfile(profile);
    const entries = Object.entries(variants || {});
    if (!entries.length) {
        return '';
    }
    const adultMode = storyMode === 'adult' && !!state?.adultContent?.enabled;
    const card = state ? characterCardForProfile(state, profile) : {};
    const activeSpeakerCandidates = [
        profile.id,
        id,
        profile.aliasOf,
        characterImageAliasMap[profile.id],
        characterImageAliasMap[id],
    ].filter(Boolean).map(String);
    const activeSpeaker = !!activeSpeakerId && activeSpeakerCandidates.includes(String(activeSpeakerId));
    const desiredPose = activeSpeaker ? (segment?.pose || card?.currentPose || card?.pose || '') : (card?.currentPose || card?.pose || '');
    const desiredExpression = activeSpeaker ? (segment?.expression || card?.currentExpression || card?.expression || '') : (card?.currentExpression || card?.expression || '');
    const desiredOutfit = card?.currentOutfit || card?.outfit || '';
    const textSignals = spriteVariantSignalsFromText(stageText || '', {
        state,
        storyMode,
        profile,
        segment,
    });
    const candidates = entries
        .filter(([key, value]) => value
            && (spriteVariantModeAllowed(key, { adultMode }) || allowMainStageAdultSpriteFallback(profile, key))
            && (allowGrokMainStage || !String(key || '').includes('.grok.')))
        .map(([key, value]) => {
            const scored = scoreSpriteVariantKey(key, {
                adultMode,
                desiredPose,
                desiredExpression,
                desiredOutfit,
                activeSpeaker,
                textSignals,
            });
            const mainStageFallback = !adultMode && allowMainStageAdultSpriteFallback(profile, key);
            return {
                key,
                value,
                score: scored.score + (mainStageFallback ? 76 : 0),
                signalHits: scored.signalHits,
            };
        })
        .sort((a, b) => b.score - a.score);
    const best = candidates[0];
    if (!best) {
        return null;
    }
    return {
        key: best.key,
        image: preferBitmapImageUrl(best.value, id || profile.id || ''),
        score: best.score,
        signalHits: best.signalHits || [],
        candidates: candidates.slice(0, 5).map((item) => ({
            key: item.key,
            score: item.score,
            signalHits: item.signalHits || [],
        })),
    };
}

function resolveCharacterSpriteVariantImage(profile = {}, options = {}) {
    return resolveCharacterSpriteVariantAsset(profile, options)?.image || '';
}

function hasCharacterSpriteAsset(profile = {}, options = {}) {
    const id = profile.id || '';
    return !!(userCharacterImageMap[`${id}_sprite`]
        || resolveCharacterSpriteVariantImage(profile, options)
        || generatedCharacterSpriteMap[id]);
}

function recordMissingVisualAsset(state, item = {}) {
    if (!state?.visuals || !item.kind || !item.id) {
        return false;
    }
    pruneResolvedMissingVisualAssets(state);
    state.visuals.missingAssetQueue = Array.isArray(state.visuals.missingAssetQueue) ? state.visuals.missingAssetQueue : [];
    const key = `${item.kind}:${item.id}:${item.variant || item.context || ''}`;
    const existing = state.visuals.missingAssetQueue.find((entry) => entry.key === key);
    const entry = {
        key,
        kind: item.kind,
        id: String(item.id || ''),
        name: item.name || item.id,
        variant: item.variant || '',
        context: item.context || '',
        prompt: item.prompt || '',
        reason: item.reason || '运行时缺少精确素材，已记录给素材窗口补图。',
        status: 'queued',
        lastSeenAt: new Date().toISOString(),
        hits: 1,
    };
    if (existing) {
        existing.lastSeenAt = entry.lastSeenAt;
        existing.hits = Math.min(999, Number(existing.hits || 1) + 1);
        existing.reason = entry.reason;
        existing.prompt ||= entry.prompt;
    } else {
        state.visuals.missingAssetQueue.unshift(entry);
        state.visuals.missingAssetQueue = state.visuals.missingAssetQueue.slice(0, 80);
    }
    state.flags ??= {};
    state.flags.lastMissingAsset = `${entry.kind}:${entry.name}`;
    return true;
}

function profileForMissingVisualAsset(entry = {}) {
    const id = String(entry.id || '').trim();
    const name = String(entry.name || '').trim();
    return allCharacterProfiles().find((profile) => {
        if (profile.id === id || profile.name === id || profile.name === name) {
            return true;
        }
        return aliasListForProfile(profile).some((alias) => alias === id || alias === name);
    }) || {
        id,
        name: name || id,
    };
}

function isMissingVisualAssetResolved(entry = {}) {
    if (!entry?.kind || !entry?.id) {
        return false;
    }
    if (entry.kind === 'character_sprite') {
        const profile = profileForMissingVisualAsset(entry);
        return hasCharacterSpriteAsset(profile, { storyMode: entry.variant || 'base' }) || !!profile.image;
    }
    if (entry.kind === 'scene_background') {
        const id = String(entry.id || '').trim();
        const backdrop = sceneBackdropByKey[id];
        return !!(backdrop && sceneBackdropImageUrl(backdrop, { mode: 'adaptive', imageUrl: '' }));
    }
    return false;
}

function pruneResolvedMissingVisualAssets(state) {
    if (!state?.visuals || !Array.isArray(state.visuals.missingAssetQueue) || !state.visuals.missingAssetQueue.length) {
        return 0;
    }
    const before = state.visuals.missingAssetQueue.length;
    state.visuals.missingAssetQueue = state.visuals.missingAssetQueue.filter((entry) => !isMissingVisualAssetResolved(entry));
    const removed = before - state.visuals.missingAssetQueue.length;
    if (removed > 0) {
        state.flags ??= {};
        state.flags.lastMissingAsset = state.visuals.missingAssetQueue[0]
            ? `${state.visuals.missingAssetQueue[0].kind}:${state.visuals.missingAssetQueue[0].name || state.visuals.missingAssetQueue[0].id}`
            : '';
        state.flags.lastMissingAssetPrune = `${removed} resolved item(s) pruned`;
    }
    return removed;
}

function resolveCharacterStageAsset(profile = {}, options = {}) {
    const variantAsset = resolveCharacterSpriteVariantAsset(profile, options);
    const variant = variantAsset?.image || '';
    const hasSprite = hasCharacterSpriteAsset(profile, options);
    if (!hasSprite) {
        recordMissingVisualAsset(options.state, {
            kind: 'character_sprite',
            id: profile.id || profile.name || 'unknown',
            name: profile.name || profile.id || '未知角色',
            variant: options.storyMode || 'base',
            context: options.segment?.type || '',
            prompt: `为 ${profile.name || profile.id || '未知角色'} 生成 Galgame 透明扣图立绘：半身/全身差分、透明背景、动漫视觉小说风格、与当前角色设定一致。`,
            reason: '当前角色只有头像/画像可用，缺少 Galgame 舞台立绘。',
        });
    }
    return {
        mode: hasSprite ? 'sprite' : 'portrait',
        image: hasSprite ? (variant || resolveCharacterSpriteImage(profile)) : resolveCharacterImage(profile),
        fallback: fallbackCharacterImage(profile),
        variant: variant || '',
        variantKey: variantAsset?.key || '',
        matchScore: Number(variantAsset?.score || 0),
        matchReason: variantAsset?.signalHits?.length
            ? `差分命中 ${variantAsset.signalHits.slice(0, 5).join(' / ')}`
            : (variantAsset?.key ? `默认差分 ${variantAsset.key}` : '头像/基础立绘兜底'),
        candidates: variantAsset?.candidates || [],
    };
}

function adultGrokBridgeIntensity(state, segment = null, storyMode = '') {
    if (storyMode !== 'adult' || !state?.adultContent?.enabled) {
        return 0;
    }
    const source = [
        state.current?.location,
        state.gameplay?.activeObjective,
        state.gameplay?.lastPlayerAction,
        state.gameplay?.lastOutcome,
        segment?.speakerName,
        segment?.speakerId,
        segment?.text,
        segment?.action,
        segment?.tone,
        segment?.pose,
        segment?.expression,
        segment?.camera,
        segment?.focus,
        segment?.sfx,
        ...(state.adultContent?.lastTensionLog || []).slice(-3),
    ].filter(Boolean).join(' ');
    let score = state.adultContent?.sceneGate?.status === 'open' ? 22 : 14;
    const patterns = [
        [/嫉妒|占有|不许|只看着|吃醋|独占/u, 18],
        [/命令|支配|服从|主从|跪|低头|不容拒绝/u, 18],
        [/危险|猎物|刀|杀意|追杀|反咬|暗杀者/u, 16],
        [/誓约|契约|破誓|权力|崩塌|屈服|压迫/u, 16],
        [/魔女|影子|黑线|银线|嫉妒魔女|梦境|仪式/u, 16],
        [/卧室|寝室|夜袍|床边|私室|独处|雨窗|帐篷|马车/u, 12],
        [/吻|拥抱|贴近|低语|呼吸|脸红|气息|欲言又止|主动靠近/u, 12],
        [/风暴|暴雨|破晓|余温|事后|照料|披肩/u, 10],
    ];
    for (const [pattern, weight] of patterns) {
        if (pattern.test(source)) {
            score += weight;
        }
    }
    return Math.max(0, Math.min(100, score));
}

function grokAdultSpriteVariantsForProfile(profile = {}) {
    const ids = [profile.id, characterImageAliasMap[profile.id], profile.aliasOf]
        .filter(Boolean)
        .map((id) => String(id));
    for (const id of ids) {
        const variants = generatedCharacterSpriteVariantMap[id] || {};
        const entries = Object.entries(variants).filter(([key, file]) => file && String(key || '').includes('.grok.'));
        if (entries.length) {
            return { id, entries };
        }
    }
    return { id: profile.id || '', entries: [] };
}

function grokAdultInsertCgCandidates(state, cast = [], script = null, storyMode = '') {
    if (storyMode !== 'adult' || state?.adultContent?.enabled !== true) {
        return [];
    }
    const segment = script?.currentSegment || null;
    const intensity = adultGrokBridgeIntensity(state, segment, storyMode);
    if (intensity < 34) {
        return [];
    }
    const activeId = segment?.speakerId || '';
    const sourceText = [
        segment?.text,
        segment?.action,
        segment?.tone,
        segment?.pose,
        segment?.expression,
        segment?.camera,
        segment?.focus,
        segment?.sfx,
        state.current?.location,
        state.gameplay?.activeObjective,
    ].filter(Boolean).join(' ');
    const ordered = [
        ...cast.filter((profile) => profile?.id && profile.id === activeId),
        ...cast.filter((profile) => profile?.id && profile.id !== activeId),
    ];
    const seenProfiles = new Set();
    const scored = [];
    for (const profile of ordered) {
        if (!profile?.id || seenProfiles.has(profile.id)) {
            continue;
        }
        seenProfiles.add(profile.id);
        const { id, entries } = grokAdultSpriteVariantsForProfile(profile);
        if (!entries.length) {
            continue;
        }
        const textSignals = spriteVariantSignalsFromText(sourceText, {
            state,
            storyMode,
            profile,
            segment,
        });
        for (const [key, file] of entries) {
            const variantScore = scoreSpriteVariantKey(key, {
                adultMode: true,
                desiredPose: segment?.pose || '',
                desiredExpression: segment?.expression || '',
                desiredOutfit: characterCardForProfile(state, profile)?.currentOutfit || '',
                activeSpeaker: profile.id === activeId,
                textSignals,
            });
            scored.push({
                id,
                name: profile.name || id,
                key,
                file,
                score: intensity + variantScore.score + (profile.id === activeId ? 28 : 0),
                reason: `Grok王炸插图 · 强度${intensity} · ${variantScore.signalHits.slice(0, 4).join(' / ') || '成人高强度桥段'}`,
            });
        }
    }
    return scored
        .sort((a, b) => b.score - a.score || a.key.localeCompare(b.key))
        .slice(0, 2);
}

function grokAdultInsertCgMarkup(state, cast = [], script = null, storyMode = '') {
    if (storyMode !== 'adult' || state?.adultContent?.enabled !== true) {
        state.visuals ??= {};
        state.visuals.grokAdultInsertCg = {
            active: false,
            count: 0,
            reason: 'adult insert CG disabled outside adult story mode',
            summary: externalGrokAdultRuntimeSummary,
        };
        return '';
    }
    const candidates = grokAdultInsertCgCandidates(state, cast, script, storyMode);
    if (!candidates.length) {
        state.visuals ??= {};
        state.visuals.grokAdultInsertCg = {
            active: false,
            count: 0,
            reason: 'adult intensity below threshold',
            summary: externalGrokAdultRuntimeSummary,
        };
        return '';
    }
    state.visuals ??= {};
    state.visuals.grokAdultInsertCg = {
        active: true,
        count: candidates.length,
        characterIds: candidates.map((item) => item.id),
        variantKeys: candidates.map((item) => item.key),
        reason: candidates[0]?.reason || '',
        summary: externalGrokAdultRuntimeSummary,
        referenceImages: candidates.flatMap((item) => (externalGrokAdultReferenceMap[item.id] || []).slice(0, 1)),
    };
    return candidates.map((item, index) => `
        <figure class="re0-vn-insert-cg re0-vn-insert-cg-${index + 1}"
            data-re0-vn-insert-cg="${escapeHtml(item.id)}"
            data-re0-vn-insert-cg-variant="${escapeHtml(item.key)}"
            data-re0-vn-insert-cg-score="${escapeHtml(Math.round(item.score))}"
            title="${escapeHtml(item.name)} · ${escapeHtml(item.reason)}">
            <img src="${escapeHtml(preferBitmapImageUrl(item.file, item.id))}" alt="${escapeHtml(item.name)} 成人桥段插图" loading="lazy">
            <figcaption>${escapeHtml(item.name)} · 插入CG</figcaption>
        </figure>
    `).join('');
}

function generatedAvatarPath(id) {
    return `${GENERATED_ASSET_ROOT}/avatars/${encodeURIComponent(id)}.jpg`;
}

function generatedScenePath(key) {
    return `${GENERATED_ASSET_ROOT}/scenes/${encodeURIComponent(key)}.png`;
}

function isVectorImageUrl(value) {
    return /\.svg(?:$|[?#])/i.test(String(value || ''));
}

function preferBitmapImageUrl(value, id = '') {
    const source = String(value || '').trim();
    if (!source || !isVectorImageUrl(source)) {
        return source;
    }
    if (/\/avatars\//i.test(source)) {
        return generatedAvatarPath(id || 'unknown');
    }
    return source.replace(/\.svg(?=$|[?#])/i, '.png');
}

async function loadUserAssetManifest() {
    try {
        const response = await fetch(`${USER_ASSET_ROOT}/manifest.json?ts=${Date.now()}`, { cache: 'no-store' });
        if (!response.ok) {
            return;
        }
        const manifest = await response.json();
        userCharacterImageMap = manifest?.avatars && typeof manifest.avatars === 'object' ? manifest.avatars : {};
        userSceneImageMap = manifest?.scenes && typeof manifest.scenes === 'object' ? manifest.scenes : {};
        refreshStatePrompt();
        renderHud();
        decorateChatMessages();
    } catch (error) {
        console.warn('[Re0AdventureEngine] Failed to load user asset manifest', error);
    }
}

