function adultPreferenceForProfile(profileOrName = {}, patch = {}) {
    const profile = typeof profileOrName === 'string' ? { name: profileOrName } : (profileOrName || {});
    const key = String(profile.id || '').toLowerCase();
    const name = String(profile.name || patch.name || profileOrName || '');
    const normalizedName = name.replace(/\s+/g, '');
    const explicit = adultPreferenceProfiles[key] || adultPreferenceProfiles[normalizedName] || adultPreferenceProfiles[name];
    const fallback = fallbackAdultPreferenceSets[Math.abs(Number(hashString(key || normalizedName || 'adult-pref'))) % fallbackAdultPreferenceSets.length];
    return {
        sexualKinks: normalizeTextArray(mergeLoreArrays(explicit?.sexualKinks || fallback.sexualKinks, patch.sexualKinks || patch.kinks || patch.intimatePreferences), 10, sanitizeAdultOnlyText),
        hobbies: normalizeTextArray(mergeLoreArrays(explicit?.hobbies || fallback.hobbies, patch.hobbies || patch.likes || patch.preferences), 10, sanitizeAdultOnlyText),
        routeStrategy: sanitizeAdultOnlyText(patch.routeStrategy || explicit?.routeStrategy || adultOnlyCueFor(name, patch)),
        intimacyExperience: sanitizeAdultOnlyText(patch.intimacyExperience || patch.sexualExperience || explicit?.intimacyExperience || '未记录；随本存档剧情推进更新。'),
    };
}

function withIntimacyMetadata(targets = {}) {
    return Object.fromEntries(Object.entries(targets || {}).map(([name, route]) => {
        const profile = intimacyProfiles[name] || { scope: 'none', cue: '未确认成年或不适合成人亲密线；只允许普通羁绊。' };
        return [name, {
            ...route,
            intimacyScope: route.intimacyScope || profile.scope,
            romanceCue: route.romanceCue || profile.cue,
        }];
    }));
}

