        嫉妒: 'betrayal_jealousy',
        主从: 'consensual_power_exchange',
        支配: 'consensual_power_exchange',
        服从: 'consensual_power_exchange',
        domsub: 'consensual_power_exchange',
        虐恋: 'tragic_romance',
        悲恋: 'tragic_romance',
