        female: adultFemaleProfileIds.has(profile.id) || /(女性|女仆|候补|魔女|修女|女王|贵妇|城主|成年女性)/.test(text),
        authority: /(王选|当主|皇帝|领袖|城主|贵妇|边境伯|骑士|将领|商会|公爵|剑圣|九神将)/.test(text),
