function profileAllowsAdultTag(profile, tag, card = {}) {
    if (!adultRelationshipTagCatalog[tag]) {
        return false;
    }
    const trait = adultProfileTrait(profile, card);
    if (tag === 'women_love') {
        return trait.female;
    }
    if (tag === 'dangerous_attraction' || tag === 'dark_horror_romance') {
        return trait.dangerous || trait.analytical || Number(card.trauma || 0) >= 25;
    }
    return true;
}

