function syncAdultSettingTagsToCharacterCards(state) {
    if (!state?.adultContent?.enabled) {
        return false;
    }
    state.characterCards ??= {};
    let changed = false;
    for (const profile of allCharacterProfiles()) {
        if (!profile?.id || profile.id === 'narrator' || profile.id === 'protagonist') {
            continue;
        }
        const card = ensureCharacterCard(state, profile.name, {
            id: profile.id,
            role: profile.role,
            name: profile.name,
            lastUpdatedDay: Number(state.current?.day) || 1,
        });
        if (!card) {
            continue;
        }
        const previousDerived = normalizeTextArray(card.adultSettingKinks, 16, sanitizeAdultOnlyText);
        const baseKinks = normalizeTextArray(card.sexualKinks || card.kinks || card.intimatePreferences, 16, sanitizeAdultOnlyText)
            .filter((item) => !previousDerived.includes(item));
        const settingKinks = adultSettingKinksForProfile(state, profile, card);
        const settingTags = adultSettingTagsForProfile(state, profile, card);
        card.adultSettingTags = settingTags;
        card.adultSettingKinks = settingKinks;
        card.sexualKinks = mergeArrayUnique(baseKinks, settingKinks, 16).map(sanitizeAdultOnlyText);
        card.intimatePreferences = card.sexualKinks;
        card.flags = mergeArrayUnique(card.flags, ['adult-setting-kinks-synced'], 16);
        card.arcLog = mergeArrayUnique(card.arcLog, [
            `成人设定词条同步为癖好：${adultTagLabels(settingTags).join('、') || '无'}`,
        ], 18);
        changed = true;
    }
    if (changed) {
        state.adultContent.relationshipSyncLog = mergeArrayUnique(state.adultContent.relationshipSyncLog || [], [
            `成人设定词条已同步到角色癖好：${adultTagLabels(activeAdultRelationshipTags(state)).join('、') || '无'}`,
        ], 18);
        state.flags ??= {};
        state.flags.lastCharacterCardSync = '成人设定词条已同步到所有角色癖好';
    }
    return changed;
}

function isPlaceholderIntimacyExperience(value) {
    return !value || /^(未记录|暂无|等待|第一次有效亲密推进后|随本存档剧情推进更新)/.test(String(value).trim());
}

function normalizeIntimacyHistory(card = {}, limit = 8) {
    const raw = [
        ...(Array.isArray(card.intimacyHistory) ? card.intimacyHistory : []),
        ...(Array.isArray(card.intimacyExperiences) ? card.intimacyExperiences : []),
        card.intimacyExperience,
        card.sexualExperience,
    ];
    return normalizeTextArray(raw, limit, sanitizeAdultOnlyText)
        .filter((item) => !isPlaceholderIntimacyExperience(item));
}

function latestIntimacyExperience(card = {}, fallback = '未记录；第一次有效亲密推进后写入本存档角色卡。') {
    const history = normalizeIntimacyHistory(card);
    if (history.length) {
        return history.at(-1);
    }
    const direct = sanitizeAdultOnlyText(card.intimacyExperience || card.sexualExperience || '');
    return isPlaceholderIntimacyExperience(direct) ? fallback : direct;
}

function appendIntimacyExperience(card, entry, limit = 8) {
    if (!card || isPlaceholderIntimacyExperience(entry)) {
        return;
    }
    const nextHistory = mergeArrayUnique(normalizeIntimacyHistory(card, limit), [sanitizeAdultOnlyText(entry)], limit)
        .filter((item) => !isPlaceholderIntimacyExperience(item));
    card.intimacyHistory = nextHistory;
    card.intimacyExperience = nextHistory.at(-1) || '';
    card.sexualExperience = card.intimacyExperience;
}

function intimacyExperienceDisplay(card = {}, route = {}) {
    const history = normalizeIntimacyHistory(card);
    if (history.length) {
        return history.slice(-3).map((item, index) => `${index + 1}. ${item}`).join('\n');
    }
    const routeExperience = route.intimacyExperience || route.sexualExperience;
    if (!isPlaceholderIntimacyExperience(routeExperience)) {
        return sanitizeAdultOnlyText(routeExperience);
    }
    return '未记录；第一次有效亲密推进后写入本存档角色卡。';
}

function normalizeAdultOnlyCard(card = {}, name = '') {
    const preferences = adultPreferenceForProfile({ id: card.id, name: name || card.name }, card);
    const intimacyHistory = normalizeIntimacyHistory(card);
    const next = {
        ...card,
        adultStatus: 'confirmed-adult',
        adultVariant: 'adult-only-au',
        ageDescriptor: '成年外观、成年身份、成年社会责任',
        adultContinuityOverlay: '成人向存档重映射：该角色在本世界线中为成年版本；任何未成年/幼态原作语义不参与本存档。',
        role: sanitizeAdultOnlyText(card.role || ''),
        personality: sanitizeAdultOnlyText(card.personality || ''),
        attitudeToPlayer: sanitizeAdultOnlyText(card.attitudeToPlayer || ''),
        canonCore: card.canonCore,
        affection: clampPercent(card.affection ?? card.affinity ?? 0),
        desire: clampPercent(card.desire ?? card.emotionalValue ?? card.emotionalDesire ?? 0),
        intimacyHistory,
        intimacyExperience: intimacyHistory.at(-1) || preferences.intimacyExperience,
        sexualExperience: intimacyHistory.at(-1) || preferences.intimacyExperience,
        routeStrategy: preferences.routeStrategy,
        sexualKinks: preferences.sexualKinks,
        hobbies: preferences.hobbies,
        flags: mergeArrayUnique(card.flags, ['adult-only-world:confirmed-adult'], 16),
    };
    next.intimatePreferences = next.sexualKinks;
    if (!next.name) {
        next.name = name;
    }
    if (Array.isArray(next.memory)) {
        next.memory = next.memory.map(sanitizeAdultOnlyText).slice(-18);
    }
    if (Array.isArray(next.arcLog)) {
        next.arcLog = next.arcLog.map(sanitizeAdultOnlyText).slice(-18);
    }
    return next;
}

function normalizeAdultOnlyPopulationTemplate(template = {}) {
    const id = String(template.id || '').replace(/child|minor/g, 'adult');
    return {
        ...template,
        id,
        role: sanitizeAdultOnlyText(template.role || '成年群众、传话人、旁观者'),
        motive: sanitizeAdultOnlyText(template.motive || '生存、利益、庇护'),
        risk: sanitizeAdultOnlyText(template.risk || '被信息差、阶级和暴力规则利用'),
        adultStatus: 'confirmed-adult',
    };
}

function applyAdultOnlyWorld(state) {
    if (!state?.adultContent?.enabled || !state.adultContent.adultOnlyWorld) {
        return;
    }
    state.adultContent.mode = 'adult-soft';
    state.adultContent.allActiveCharactersAreAdults = true;
    state.adultContent.adultContinuityRule = buildDefaultAdultContentState().adultContinuityRule;
    const palette = adultPalette(state);
    state.adultContent.relationshipPalette = {
        ...palette,
        enabledTags: palette.enabledTags.filter((tag) => !palette.hardLimits.includes(tag) && !palette.disabledTags.includes(tag)),
        disabledTags: mergeArrayUnique(palette.disabledTags, palette.hardLimits.filter((tag) => tag === 'male_male'), 12),
        hardLimits: mergeArrayUnique(palette.hardLimits, ['minors', 'non_consent', 'explicit_genitals', 'sexualized_gore', 'male_male'], 12),
    };
    if (state.routeSystem?.targets) {
        state.routeSystem.targets = Object.fromEntries(Object.entries(state.routeSystem.targets).map(([name, route]) => [
            name,
            normalizeAdultOnlyRoute(name, route),
        ]));
    }
    if (state.characterCards) {
        for (const [name, card] of Object.entries(state.characterCards)) {
            state.characterCards[name] = completeCharacterCard(normalizeAdultOnlyCard(card, name));
        }
    }
    syncAdultSettingTagsToCharacterCards(state);
    if (state.worldScope?.populationTemplates) {
        state.worldScope.populationTemplates = state.worldScope.populationTemplates.map(normalizeAdultOnlyPopulationTemplate);
    }
}

