function buildDefaultWorldClockState() {
    const settings = extension_settings[MODULE_NAME] ?? defaultSettings;
    const turnsPerWorldDay = Math.max(1, Number(settings.backgroundTurnsPerWorldDay) || 30);
    return {
        enabled: settings.backgroundWorldClockEnabled !== false,
        worldDay: 1,
        turnsPerWorldDay,
        turnsSinceWorldDay: 0,
        turnsSinceMainlinePulse: 0,
        mainlinePulseEveryTurns: 6,
        lastTickMessageId: -1,
        lastAdvancedAtMessageId: -1,
        localConflictPolicy: '后台世界日可以领先主角当前局部日期，但不会自动改写主角眼前时段；若要追上世界时间，必须由用户输入“推进时间/进入下一天/快速跳过”。禁止在无死亡回归、读档或安全锚点的情况下把局部时间倒退。',
        history: [],
    };
}

