function buildDefaultSimulationState() {
    const configuredParallelism = Number(extension_settings[MODULE_NAME]?.worldSimParallelism || defaultSettings.worldSimParallelism || 8);
    return {
        tick: 0,
        mode: extension_settings[MODULE_NAME]?.worldSimIntensity || defaultSettings.worldSimIntensity || 'token-rich',
        parallelism: Math.max(1, Math.min(32, Number.isFinite(configuredParallelism) ? configuredParallelism : 8)),
        lastRunAt: '',
        summary: '尚未运行并发世界推演。',
        riskLevel: 'unknown',
        nextRecommendedFocus: [],
    };
}

function mergeStoryFlowClocks(baseClocks = [], patchClocks = []) {
    const map = new Map();
    for (const clock of [...(baseClocks || []), ...(patchClocks || [])]) {
        if (!clock?.id) {
            continue;
        }
        const previous = map.get(clock.id) || {};
        map.set(clock.id, {
            ...previous,
            ...clock,
            activeLocations: mergeLoreArrays(previous.activeLocations, clock.activeLocations).slice(0, 10),
            triggerWindows: mergeLoreArrays(previous.triggerWindows, clock.triggerWindows).slice(0, 12),
            entryMethods: mergeLoreArrays(previous.entryMethods, clock.entryMethods).slice(0, 8),
        });
    }
    return [...map.values()].sort((a, b) => Number(a.arc || 1) - Number(b.arc || 1) || String(a.id).localeCompare(String(b.id)));
}

