function mergeLoreArrays(defaultValue, overrideValue) {
    const normalize = (value) => Array.isArray(value) ? value : (value ? [value] : []);
    return [...new Set([...normalize(defaultValue), ...normalize(overrideValue)].filter(Boolean))];
}

function applyCharacterLore(profile) {
    const dossier = STORYLINE_DEFAULTS.characterDossiers?.[profile.id] || {};
    const staticPlan = characterDossierStaticPatch?.[profile.id] || {};
    const staticPatch = staticPlan.staticPatch || {};
    const override = {
        ...dossier,
        ...staticPatch,
        ...(characterLoreOverrides[profile.id] || {}),
    };
    return {
        ...characterLoreDefaults,
        ...profile,
        ...override,
        staticDossierPatch: staticPlan.id ? {
            source: characterDossierStaticPatchMetadata.sourceFile,
            generatedAt: characterDossierStaticPatchMetadata.generatedAt,
            requestAlias: staticPlan.requestAlias || profile.id,
            vnDialogueOwnershipHints: staticPlan.vnDialogueOwnershipHints || {},
            adultModeCompatibility: staticPlan.adultModeCompatibility || {},
            runtimeFieldCollisionWarnings: staticPlan.runtimeFieldCollisionWarnings || {},
        } : null,
        aliases: mergeLoreArrays(profile.aliases, override.aliases),
        colors: profile.colors,
        voicePrompt: override.voicePrompt || profile.voicePrompt,
        sample: override.sample || profile.sample,
        image: resolveCharacterImage(profile, override),
        routeHooks: mergeLoreArrays(characterLoreDefaults.routeHooks, override.routeHooks),
        riskTriggers: mergeLoreArrays(characterLoreDefaults.riskTriggers, override.riskTriggers),
        relationshipAxes: mergeLoreArrays(characterLoreDefaults.relationshipAxes, override.relationshipAxes),
        arcRelevance: mergeLoreArrays(characterLoreDefaults.arcRelevance, override.arcRelevance),
    };
}

function allCharacterProfiles() {
    const baseProfiles = [...characterRoster, ...worldCharacterPool];
    const knownIds = new Set(baseProfiles.map((profile) => profile.id));
    const dossierProfiles = Object.values(STORYLINE_DEFAULTS.characterDossiers || {})
        .filter((profile) => profile?.id && !knownIds.has(profile.id))
        .map((profile) => ({
            id: profile.id,
            name: profile.name,
            shortName: profile.name?.slice(0, 1) || profile.id?.slice(0, 1),
            role: profile.role || profile.faction || '剧情角色',
            aliases: [profile.name].filter(Boolean),
            colors: ['#111827', '#6b7280', '#e5e7eb'],
            voicePrompt: profile.speechStyle || '',
            sample: '',
        }));
    return [...baseProfiles, ...dossierProfiles].map(applyCharacterLore);
}

function sillyTavernGroupInfo(context = getContext()) {
    const groupId = context?.groupId || '';
    const groups = Array.isArray(context?.groups) ? context.groups : [];
    const characters = Array.isArray(context?.characters) ? context.characters : [];
    const group = groupId ? groups.find((item) => String(item.id) === String(groupId)) : null;
    if (!group) {
        return {
            active: false,
            groupId: '',
            groupName: '',
            members: [],
            lastSyncedAt: '',
        };
    }
    const disabled = new Set(group.disabled_members || []);
    const members = (group.members || []).map((avatar) => {
        const character = characters.find((item) => item.avatar === avatar) || {};
        return {
            name: character.name || String(avatar || '').replace(/\.[^.]+$/, '') || '未命名角色',
            avatar: avatar || '',
            enabled: !disabled.has(avatar),
            description: shortPromptText(character.description || character.personality || character.scenario || '', 90),
        };
    }).filter((member) => member.name).slice(0, 12);
    return {
        active: true,
        groupId: String(group.id || groupId),
        groupName: group.name || group.chat_id || 'SillyTavern 群聊',
        members,
        lastSyncedAt: new Date().toISOString(),
    };
}

function syncSillyTavernGroupCast(state, context = getContext()) {
    if (!state) {
        return false;
    }
    state.castDirector ??= buildDefaultCastDirectorState();
    const previous = JSON.stringify(state.castDirector.sillyTavernGroup || {});
    const next = sillyTavernGroupInfo(context);
    state.castDirector.sillyTavernGroup = next;
    if (next.active) {
        state.castDirector.mode = 'sillytavern-group-compatible';
        state.castDirector.lastChange = `已同步 SillyTavern 多角色群聊：${next.groupName}（${next.members.filter((member) => member.enabled).length}/${next.members.length} 名启用）。`;
    } else if (state.castDirector.mode === 'sillytavern-group-compatible') {
        state.castDirector.mode = 'character-driven';
        state.castDirector.lastChange = '当前为单角色聊天；继续用扩展当前场景人物与角色卡模拟多角色驱动。';
    }
    return previous !== JSON.stringify(state.castDirector.sillyTavernGroup || {});
}

