function loadSettings() {
    extension_settings[MODULE_NAME] ??= {};
    for (const [key, value] of Object.entries(defaultSettings)) {
        if (extension_settings[MODULE_NAME][key] === undefined) {
            extension_settings[MODULE_NAME][key] = value;
        }
    }
    extension_settings[MODULE_NAME].worldSimParallelism = Math.max(1, Math.min(12, Number(extension_settings[MODULE_NAME].worldSimParallelism) || defaultSettings.worldSimParallelism));
    saveSettingsDebounced();
}

function isTargetCharacter(context = getContext()) {
    const character = context?.characters?.[context?.characterId];
    return character?.avatar === TARGET_AVATAR || character?.name === 'Re:0 黑暗死亡回归叙事引擎';
}

