function isCoreRosterProfile(profile) {
    return characterRoster.some((item) => item.id === profile.id);
}

function buildCharacterCardFromProfile(profile, patch = {}) {
    const source = applyCharacterLore(profile || {});
    const adultPreferences = adultPreferenceForProfile(source, patch);
    const intimacyHistory = normalizeIntimacyHistory(patch);
    return {
        id: patch.id || source.id || hashString(source.name || 'character'),
        name: patch.name || source.name || '未知角色',
        role: patch.role || source.role || '剧情角色',
        faction: patch.faction || source.faction,
        canonCore: patch.canonCore || source.canonCore,
        motivation: patch.motivation || source.motivation,
        hiddenPressure: patch.hiddenPressure || source.hiddenPressure,
        knowledgeBoundaries: patch.knowledgeBoundaries || source.knowledgeBoundaries,
        routeHooks: mergeLoreArrays(source.routeHooks, patch.routeHooks),
        riskTriggers: mergeLoreArrays(source.riskTriggers, patch.riskTriggers),
        speechStyle: patch.speechStyle || source.speechStyle,
        relationshipAxes: mergeLoreArrays(source.relationshipAxes, patch.relationshipAxes),
        arcRelevance: mergeLoreArrays(source.arcRelevance, patch.arcRelevance),
        routeAvailability: patch.routeAvailability || source.routeAvailability,
        memory: patch.memory || ['尚未形成与当前世界线强绑定的个人记忆。'],
        personality: patch.personality || '保持原作/设定核心，暂未发生明显偏移。',
        attitudeToPlayer: patch.attitudeToPlayer || '未接触或仅有初始印象。',
        trust: Number.isFinite(Number(patch.trust)) ? Number(patch.trust) : 0,
        suspicion: Number.isFinite(Number(patch.suspicion)) ? Number(patch.suspicion) : 0,
        trauma: Number.isFinite(Number(patch.trauma)) ? Number(patch.trauma) : 0,
        affection: clampPercent(patch.affection ?? patch.affinity ?? 0),
        desire: clampPercent(patch.desire ?? patch.emotionalValue ?? patch.emotionalDesire ?? 0),
        conflict: clampPercent(patch.conflict ?? 0),
        intimacyHistory,
        intimacyExperience: intimacyHistory.at(-1) || adultPreferences.intimacyExperience,
        sexualExperience: intimacyHistory.at(-1) || adultPreferences.intimacyExperience,
        sexualKinks: adultPreferences.sexualKinks,
        hobbies: adultPreferences.hobbies,
        intimatePreferences: adultPreferences.sexualKinks,
        routeStrategy: adultPreferences.routeStrategy || source.routeStrategy || '',
        flags: patch.flags || [],
        arcLog: patch.arcLog || [],
        lastUpdatedDay: Number.isFinite(Number(patch.lastUpdatedDay)) ? Number(patch.lastUpdatedDay) : 1,
        saveBound: true,
        poolStatus: isCoreRosterProfile(source) ? 'hud-core' : 'world-pool',
    };
}

function findProfileByName(name) {
    const normalized = String(name || '').replace(/\s+/g, '');
    return allCharacterProfiles().find((profile) => {
        if (String(profile.name || '').replace(/\s+/g, '') === normalized) {
            return true;
        }
        return (profile.aliases || []).some((alias) => String(alias).replace(/\s+/g, '') === normalized);
    });
}

function completeCharacterCard(card) {
    const profile = findProfileByName(card?.name) || allCharacterProfiles().find((item) => item.id === card?.id);
    if (!profile) {
        return card;
    }
    const base = buildCharacterCardFromProfile(profile);
    const adultPreferences = adultPreferenceForProfile(profile, card);
    const intimacyHistory = normalizeIntimacyHistory(card);
    const intimacyExperience = intimacyHistory.at(-1) || adultPreferences.intimacyExperience || base.intimacyExperience || '';
    return {
        ...base,
        ...card,
        routeHooks: mergeLoreArrays(base.routeHooks, card.routeHooks),
        riskTriggers: mergeLoreArrays(base.riskTriggers, card.riskTriggers),
        relationshipAxes: mergeLoreArrays(base.relationshipAxes, card.relationshipAxes),
        arcRelevance: mergeLoreArrays(base.arcRelevance, card.arcRelevance),
        sexualKinks: adultPreferences.sexualKinks,
        hobbies: adultPreferences.hobbies,
        intimatePreferences: adultPreferences.sexualKinks,
        affection: clampPercent(card.affection ?? base.affection ?? 0),
        desire: clampPercent(card.desire ?? card.emotionalValue ?? base.desire ?? 0),
        conflict: clampPercent(card.conflict ?? base.conflict ?? 0),
        intimacyHistory,
        intimacyExperience,
        sexualExperience: intimacyExperience,
        routeStrategy: adultPreferences.routeStrategy || base.routeStrategy || '',
        memory: Array.isArray(card.memory) && card.memory.length ? card.memory : base.memory,
        flags: Array.isArray(card.flags) ? card.flags : base.flags,
        arcLog: Array.isArray(card.arcLog) ? card.arcLog : base.arcLog,
    };
}

function buildDefaultCharacterCards() {
    const cards = {};
    for (const profile of allCharacterProfiles()) {
        if (profile.id === 'narrator' || profile.id === 'protagonist') {
            continue;
        }
        cards[profile.name] = buildCharacterCardFromProfile(profile);
    }
    return cards;
}

