function cloneStorylineData(value) {
    return JSON.parse(JSON.stringify(value ?? null));
}

function buildDefaultConvergenceNodes() {
    return cloneStorylineData(STORYLINE_DEFAULTS.convergenceNodes || [])
        .filter((node) => currentWorldRuleAllowed(node) || String(node?.id || '') === 'C9')
        .map((node) => String(node?.id || '') === 'C9'
            ? {
                ...node,
                name: '玩家因果继承',
                rule: '原世界线关键因果、死亡回归压力、救援窗口、错误方针和行动修正机会全部集中到玩家；玩家是唯一主线行动锚点。',
                keywords: ['玩家唯一主角', '因果继承', '死亡回归', '锚点噪声'],
                status: node.status || 'active',
            }
            : node)
        .map((node) => ({
            ...node,
            status: node.status || 'active',
        }));
}

