function buildDefaultBranchTransitionState() {
    return {
        mode: 'soft-attractor',
        divergenceRate: 0.08,
        continuityIndex: 0.92,
        inertia: 0.62,
        volatility: 0.18,
        convergenceElasticity: 0.36,
        softLockThreshold: 9,
        hardLockThreshold: 16,
        lastShift: '分支仍处于连续吸引域：选择只改变偏移率和路线压力，不会一次硬切世界线。',
        lastShiftReason: '初始状态',
        updatedAt: '',
    };
}

function clampIfRoutePressure(value) {
    return Math.max(0, Math.min(30, Math.round(Number(value) || 0)));
}

function clampIfRouteMomentum(value) {
    return Math.max(-12, Math.min(12, Math.round(Number(value) || 0)));
}

function normalizeBranchTransitionState(value = {}, logic = {}) {
    const seed = buildDefaultBranchTransitionState();
    const merged = value && typeof value === 'object' ? { ...seed, ...value } : seed;
    merged.mode = merged.mode || seed.mode;
    merged.divergenceRate = clampUnit(Number(merged.divergenceRate ?? seed.divergenceRate));
    merged.continuityIndex = clampUnit(Number(merged.continuityIndex ?? seed.continuityIndex));
    merged.inertia = clampUnit(Number(merged.inertia ?? seed.inertia));
    merged.volatility = clampUnit(Number(merged.volatility ?? seed.volatility));
    merged.convergenceElasticity = clampUnit(Number(merged.convergenceElasticity ?? seed.convergenceElasticity));
    merged.softLockThreshold = Math.max(3, Math.min(24, Math.round(Number(merged.softLockThreshold || seed.softLockThreshold))));
    merged.hardLockThreshold = Math.max(merged.softLockThreshold + 1, Math.min(30, Math.round(Number(merged.hardLockThreshold || seed.hardLockThreshold))));
    merged.lastShift ||= seed.lastShift;
    merged.lastShiftReason ||= seed.lastShiftReason;
    merged.updatedAt ||= '';
    merged.continuityIndex = branchTransitionContinuityIndex({ ...logic, branchTransition: merged });
    return merged;
}

function normalizeIfRouteLogicState(value = {}) {
    const seed = buildDefaultIfRouteLogicState();
    const merged = value && typeof value === 'object' ? { ...seed, ...value } : seed;
    merged.routePressures = { ...seed.routePressures, ...(merged.routePressures || {}) };
    merged.routeMomentum = { ...seed.routeMomentum, ...(merged.routeMomentum || {}) };
    merged.axisScores = { ...seed.axisScores, ...(merged.axisScores || {}) };
    merged.lastAppliedScore = { ...seed.lastAppliedScore, ...(merged.lastAppliedScore || {}) };
    for (const id of Object.keys(ifRouteProfiles)) {
        merged.routePressures[id] = clampIfRoutePressure(merged.routePressures[id]);
        merged.routeMomentum[id] = clampIfRouteMomentum(merged.routeMomentum[id]);
        merged.lastAppliedScore[id] = clampIfRoutePressure(merged.lastAppliedScore[id]);
    }
    for (const id of Object.keys(ifRouteAxisRules)) {
        merged.axisScores[id] = clampIfRoutePressure(merged.axisScores[id]);
    }
    merged.lastSignals = Array.isArray(merged.lastSignals) ? merged.lastSignals.slice(-16) : [];
    merged.lastBranchRuleMatches = Array.isArray(merged.lastBranchRuleMatches) ? merged.lastBranchRuleMatches.slice(-12) : [];
    merged.lastGateRagRefs = Array.isArray(merged.lastGateRagRefs) ? merged.lastGateRagRefs.slice(-6) : [];
    merged.lastOfficialIfGate = merged.lastOfficialIfGate && typeof merged.lastOfficialIfGate === 'object'
        ? merged.lastOfficialIfGate
        : null;
    merged.branchRuleMetadata = {
        count: generatedIfBranchRuleMetadata.count || generatedIfBranchRules.length,
        softDivisionCount: generatedIfBranchRuleMetadata.softDivisionCount || 0,
        generatedAt: generatedIfBranchRuleMetadata.generatedAt || '',
        ...(merged.branchRuleMetadata || {}),
    };
    merged.branchTransition = normalizeBranchTransitionState(merged.branchTransition, merged);
    merged.driftLedger = Array.isArray(merged.driftLedger) ? merged.driftLedger.slice(-18) : [];
    merged.correctionLedger = Array.isArray(merged.correctionLedger) ? merged.correctionLedger.slice(-18) : [];
    merged.softLocks = Array.isArray(merged.softLocks) ? merged.softLocks.slice(-8) : [];
    merged.candidateBranches = Array.isArray(merged.candidateBranches) ? merged.candidateBranches.slice(-8) : [];
    if (!ifRouteProfiles[merged.dominant]) {
        merged.dominant = dominantIfRouteId(merged);
    }
    merged.dominantLabel = ifRouteProfiles[merged.dominant]?.label || ifRouteProfiles.EnvyMain.label;
    merged.level = ifRoutePressureLevel(merged.routePressures[merged.dominant] || 0);
    merged.dominanceGap = ifRouteDominanceGap(merged);
    return merged;
}

function ifRoutePressureLevel(score) {
    const value = Number(score || 0);
    if (value >= 14) return 'lock-risk';
    if (value >= 9) return 'strong-attractor';
    if (value >= 5) return 'branch-drift';
    if (value >= 1) return 'seed';
    return 'neutral';
}

function dominantIfRouteId(logic = {}) {
    const pressures = logic.routePressures || {};
    const entries = Object.keys(ifRouteProfiles)
        .map((id) => [id, Number(pressures[id] || 0)])
        .sort((a, b) => b[1] - a[1] || (a[0] === 'EnvyMain' ? 1 : (b[0] === 'EnvyMain' ? -1 : 0)));
    const top = entries[0] || ['EnvyMain', 0];
    return top[1] > 0 ? top[0] : 'EnvyMain';
}

function ifRouteDominanceGap(logic = {}) {
    const entries = Object.entries(logic.routePressures || {})
        .map(([id, score]) => [id, Number(score || 0)])
        .sort((a, b) => b[1] - a[1]);
    if (!entries.length) {
        return 0;
    }
    return Number((entries[0][1] - (entries[1]?.[1] || 0)).toFixed(1));
}

function ifRouteScoreLine(logic, limit = 6) {
    const pressures = normalizeIfRouteLogicState(logic).routePressures;
    return Object.entries(pressures)
        .sort((a, b) => Number(b[1] || 0) - Number(a[1] || 0))
        .slice(0, limit)
        .map(([id, score]) => `${ifRouteProfiles[id]?.label || id}:${score}`)
        .join(' / ');
}

function ifRouteAxisScoreLine(logic, limit = 6) {
    const axisScores = normalizeIfRouteLogicState(logic).axisScores || {};
    return Object.entries(axisScores)
        .sort((a, b) => Number(b[1] || 0) - Number(a[1] || 0))
        .slice(0, limit)
        .map(([id, score]) => `${ifRouteAxisRules[id]?.label || id}:${score}`)
        .join(' / ');
}

function ifRouteSourceWeight(source = 'narration') {
    const table = {
        user: 2,
        death: 3,
        failure: 2,
        narration: 1,
        fallback: 1,
        worldSim: 1,
    };
    return table[source] || 1;
}

