function scoreSceneAssetForContext(backdrop = {}, context = {}, index = 0) {
    const baseScore = scoreSceneAssetForText(backdrop, context.searchText || '');
    const boosts = semanticSceneBackdropBoosts(context).filter((item) => item.key === backdrop.key);
    const semanticScore = boosts.reduce((total, item) => total + Number(item.score || 0), 0);
    const locationKey = backdropKeyForLocation(context.currentLocation || '');
    const locationScore = locationKey && locationKey === backdrop.key ? 42 : 0;
    const source = `${context.currentTime || ''} ${context.currentLocation || ''} ${context.searchText || ''} ${context.narrativeText || ''}`;
    const conflictPenalty = (() => {
        const key = String(backdrop.key || '');
        const rainyDeathAnchor = /雨夜|雨水|雨声|黑伞|湿冷|石板|死亡回归|返回锚点|幻痛|旧伤疤|钟声|废钟/u.test(source);
        const indoorPrivate = /室内|房间|卧室|客房|浴场|书房|酒馆楼上|帐篷|马车/u.test(source);
        if (rainyDeathAnchor && /market_day|royal_capital/u.test(key)) return -55;
        if (/深夜|夜晚|雨夜|黑暗|潜行/u.test(source) && /market_day/u.test(key)) return -35;
        if (/白天|日间|阳光|街市|市场|摊贩/u.test(source) && /rain_bell|death_anchor|witch_dream/u.test(key) && !rainyDeathAnchor) return -18;
        if (indoorPrivate && /market_day|royal_capital|capital_gate/u.test(key)) return -24;
        return 0;
    })();
    const timeScore = (() => {
        const key = String(backdrop.key || '');
        if (/夜|夜晚|深夜|雨夜|黄昏|暮色|dusk|night/i.test(source) && /night|dusk|rain|candle|witch|adult|rooftops|camp|inn/u.test(key)) return 5;
        if (/白天|上午|早晨|日间|day|morning/i.test(source) && /day|morning|market|gate|exterior/u.test(key)) return 5;
        return 0;
    })();
    const score = baseScore + semanticScore + locationScore + timeScore + conflictPenalty + (index / 10000);
    return {
        score,
        baseScore,
        semanticScore,
        locationScore,
        timeScore,
        conflictPenalty,
        reasons: [
            locationScore ? '当前地点直达' : '',
            ...boosts.map((item) => item.reason).filter(Boolean),
            timeScore ? '时间/天气吻合' : '',
            conflictPenalty ? '自然语言天气/锚点冲突惩罚' : '',
        ].filter(Boolean),
    };
}

function sceneBackdropConfidence(score = 0, strategy = 'keyword') {
    if (strategy === 'manual' || strategy === 'script' || strategy === 'location') {
        return strategy;
    }
    if (score >= 12) return 'high';
    if (score >= 4) return 'medium';
    if (score > 0) return 'low';
    return 'fallback';
}

function sceneBackdropCandidateDiagnostics(state, modeTemplate = null, {
    limit = 22,
    requiredBoost = false,
} = {}) {
    const visualState = state?.visuals?.sceneBackdrop || {};
    const context = sceneBackdropContextTerms(state, modeTemplate);
    const template = context.template;
    const searchText = context.searchText;
    const requiredKeys = new Set([
        visualState.currentKey || 'rain_bell',
        visualState.lastAutoKey || '',
        state?.visuals?.visualNovel?.backgroundKey || '',
        preferredBackdropKeyForCurrentState(state),
        state?.answerBook?.active ? 'answer_book' : '',
    ].filter(Boolean));
    const adultVisualsAllowed = state?.adultContent?.enabled === true || state?.narrativeMode?.current === 'adult' || modeTemplate?.mode === 'adult';
    const scored = sceneBackdropCatalog
        .filter((backdrop) => backdrop?.source !== 'grokadult' || adultVisualsAllowed)
        .map((backdrop, index) => {
            const scoredContext = scoreSceneAssetForContext(backdrop, context, index);
            const boostedScore = scoredContext.score + (requiredBoost && requiredKeys.has(backdrop.key) ? 20 : 0);
            return {
                backdrop,
                index,
                baseScore: scoredContext.baseScore,
                semanticScore: scoredContext.semanticScore,
                locationScore: scoredContext.locationScore,
                timeScore: scoredContext.timeScore,
                conflictPenalty: scoredContext.conflictPenalty,
                reasons: scoredContext.reasons,
                score: boostedScore > 0 ? boostedScore + (index / 10000) : 0,
            };
        })
        .sort((a, b) => b.score - a.score || b.baseScore - a.baseScore || a.index - b.index);
    const selected = [];
    const seen = new Set();
    for (const item of scored) {
        if (seen.has(item.backdrop.key)) continue;
        if (item.score <= 0 && selected.length >= Math.max(8, Math.floor(limit / 2))) continue;
        selected.push({
            key: item.backdrop.key,
            title: item.backdrop.title,
            file: sceneAssetFileName(item.backdrop),
            score: Number(item.score.toFixed(3)),
            baseScore: Number(item.baseScore.toFixed(3)),
            semanticScore: Number(item.semanticScore.toFixed(3)),
            locationScore: Number(item.locationScore.toFixed(3)),
            timeScore: Number(item.timeScore.toFixed(3)),
            conflictPenalty: Number(item.conflictPenalty.toFixed(3)),
            reasons: item.reasons || [],
            hasImage: !!sceneBackdropImageUrl(item.backdrop, { ...visualState, mode: 'adaptive', imageUrl: '' }),
            summary: item.backdrop.summary || '',
        });
        seen.add(item.backdrop.key);
        if (selected.length >= limit) break;
    }
    return {
        searchText: shortPromptText(searchText, 480),
        templateLabel: template.label || '',
        requiredKeys: [...requiredKeys],
        bestScore: selected[0]?.score ?? 0,
        candidateKeys: selected.map((item) => item.key),
        candidates: selected,
    };
}

function recordSceneBackdropMatchState(state, backdrop = {}, diagnostics = {}, {
    strategy = 'keyword',
    score = null,
    reason = '',
} = {}) {
    if (!state?.visuals?.sceneBackdrop || !backdrop?.key) {
        return null;
    }
    const visualState = state.visuals.sceneBackdrop;
    const numericScore = Number(score ?? diagnostics.bestScore ?? 0) || 0;
    const match = {
        key: backdrop.key,
        title: backdrop.title || backdrop.key,
        strategy,
        confidence: sceneBackdropConfidence(numericScore, strategy),
        score: Number(numericScore.toFixed(3)),
        reason: reason || backdrop.matchReason || visualState.lastReason || '',
        candidateKeys: Array.isArray(diagnostics.candidateKeys) ? diagnostics.candidateKeys.slice(0, 12) : [backdrop.key],
        candidates: Array.isArray(diagnostics.candidates) ? diagnostics.candidates.slice(0, 8) : [],
        searchText: diagnostics.searchText || '',
        updatedAt: new Date().toISOString(),
    };
    visualState.lastMatch = match;
    return match;
}

function shouldRecordLowConfidenceSceneBackdrop(state, diagnostics = {}, backdrop = {}) {
    if (!state?.visuals || state.visuals.sceneBackdrop?.mode === 'manual') {
        return false;
    }
    if (state.answerBook?.active || ['death_anchor', 'answer_book', 'worldline_tree', 'witch_interference', 'witch_dream'].includes(backdrop?.key)) {
        return false;
    }
    const source = [
        state.current?.location,
        state.current?.time,
        state.gameplay?.activeObjective,
        state.gameplay?.lastPlayerAction,
        state.visuals?.sceneBackdrop?.lastNarrativeText,
    ].filter(Boolean).join(' ');
    if (String(source).trim().length < 8 || /未知地点|等待下一段|雨声压低/u.test(source)) {
        return false;
    }
    return Number(diagnostics.bestScore || 0) <= 0;
}

function recordLowConfidenceSceneBackdropNeed(state, diagnostics = {}, backdrop = {}) {
    if (!shouldRecordLowConfidenceSceneBackdrop(state, diagnostics, backdrop)) {
        return false;
    }
    const location = String(state.current?.location || 'unknown_scene').trim();
    return recordMissingVisualAsset(state, {
        kind: 'scene_background',
        id: `natural:${location}`.slice(0, 96),
        name: location || '未覆盖自然语言场景',
        variant: state.narrativeMode?.current || 'daily',
        context: diagnostics.searchText || location,
        prompt: `补齐 Galgame 16:9 位图背景：${location}。当前时间=${state.current?.time || '未知'}；目标=${state.gameplay?.activeObjective || '未定'}；自然语言线索=${shortPromptText(diagnostics.searchText || '', 220)}。要求：日系暗黑奇幻视觉小说背景，无文字水印，正文区域可读。`,
        reason: `自然语言场景匹配低置信，当前只能退回 ${backdrop?.key || '默认背景'}。`,
    });
}

function sceneAssetIndexCandidates(state, limit = 22) {
    const diagnostics = sceneBackdropCandidateDiagnostics(state, null, { limit, requiredBoost: true });
    return diagnostics.candidates.map((item) => sceneBackdropByKey[item.key]).filter(Boolean);
}

function sceneAssetIndexForPrompt(state, limit = 22) {
    return sceneAssetIndexCandidates(state, limit).map((backdrop) => {
        const keywords = (backdrop.keywords || []).slice(0, 8).join('/');
        return `- key=${backdrop.key} | file=${sceneAssetFileName(backdrop)} | title=${backdrop.title} | content=${shortPromptText(backdrop.summary || backdrop.prompt || '', 96)} | tags=${keywords}`;
    }).join('\n') || '- key=rain_bell | file=arc01_slum_alley_night.png | title=王都贫民区雨夜 | content=默认雨夜开场背景';
}

function characterSpriteVariantSummary(id = '', limit = 8) {
    const variants = generatedCharacterSpriteVariantMap[id] || {};
    const keys = Object.keys(variants).filter(Boolean);
    const baseCount = keys.filter((key) => key.startsWith('base.')).length;
    const adultCount = keys.filter((key) => key.startsWith('adult.')).length;
    const grokCount = keys.filter((key) => key.includes('.grok.')).length;
    const sample = keys.slice(0, limit).join(' / ');
    return {
        count: keys.length,
        baseCount,
        adultCount,
        grokCount,
        sample,
    };
}

function characterAssetIndexForPrompt(state, limit = 12) {
    const vn = state?.visuals?.visualNovel || {};
    const presence = inferPresence(state || {});
    const candidateProfiles = uniqueProfiles([
        ...(Array.isArray(vn.castIds) ? vn.castIds.map((id) => getProfile(id) || profileFromSpeakerLabel(id)) : []),
        ...(Array.isArray(vn.sceneCharacters) ? profilesFromNames(vn.sceneCharacters, limit) : []),
        ...(Array.isArray(presence?.sceneCharacters) ? profilesFromNames(presence.sceneCharacters, limit) : []),
        vn.currentSpeakerId ? getProfile(vn.currentSpeakerId) : null,
        vn.currentSpeakerName ? profileFromSpeakerLabel(vn.currentSpeakerName) : null,
    ].filter(Boolean), limit);
    const fallbackIds = ['protagonist', 'emilia', 'felt', 'lishelle', 'mia', 'rem', 'ram', 'echidna']
        .map((id) => getProfile(id))
        .filter(Boolean);
    const profiles = candidateProfiles.length ? candidateProfiles : fallbackIds.slice(0, Math.min(limit, fallbackIds.length));
    return profiles.map((profile) => {
        const id = characterImageAliasMap[profile.id] || profile.id;
        const variants = characterSpriteVariantSummary(id, 7);
        const sources = [
            generatedCharacterSpriteMap[id] ? 'sprite' : '',
            generatedCharacterImageMap[id] || characterImageMap[id] || remoteCharacterImageMap[id] ? 'portrait' : '',
            sourceNovelCharacterImageMap[id] ? 'source-copy' : '',
        ].filter(Boolean).join('+') || 'missing';
        return `- id=${id} | name=${profile.name || id} | sources=${sources} | variants=${variants.count} (base=${variants.baseCount}, adult=${variants.adultCount}, grok=${variants.grokCount}) | keys=${variants.sample || 'none'}`;
    }).join('\n') || '- id=protagonist | name=主角 | sources=sprite | variants=base';
}

function visualNovelQueueContinuationBrief(state) {
    const vn = state?.visuals?.visualNovel || {};
    const segments = Array.isArray(vn.segments) ? vn.segments : [];
    if (!segments.length) {
        return '队列续写：当前 VN 文本队列为空；本轮写第一批可播放正文，但后续轮次必须只追加新段。';
    }
    const currentIndex = Math.max(0, Math.min(segments.length - 1, Number(vn.currentIndex) || 0));
    const tail = segments.slice(Math.max(0, currentIndex - 2), Math.min(segments.length, currentIndex + 3));
    const latest = segments.slice(-3);
    const format = (segment, index) => `${index + 1}.${segment.type === 'dialogue' ? (segment.speakerName || segment.speakerId || '角色') : '旁白'}:${shortPromptText(segment.text || '', 30)}`;
    const replayAnchors = Array.from(new Set([
        ...segments.slice(0, 2),
        ...tail,
        ...latest,
    ].map((segment) => shortPromptText(segment?.text || '', 34)).filter((text) => text.length >= 10))).slice(0, 8);
    return [
        `队列续写：当前 VN 队列 index=${currentIndex + 1}/${segments.length}，本轮回复会追加到队尾，点击播放只消费缓存队列；等待模型时本地不会伪造新剧情。`,
        `当前窗口定位锚点：${tail.map(format).join(' / ') || '无'}`,
        `队尾定位锚点：${latest.map(format).join(' / ') || '无'}`,
        `已播放禁止复述短锚点：${replayAnchors.join(' / ') || '无'}`,
        '硬规则：以上内容只用于定位队列，不是可复制正文素材；不得复述这些片段或禁止锚点，不得从“开门、抵达、走进、第一幕开场、建档确认”重新写；若当前地点/背景延续，开头必须接着队尾写新动作、新反应或新代价。上一轮已经揭示的事实不能换句式重述，追问细节时必须追加新的经手人、原因、代价、时间线、证物或拒绝理由。',
    ].join('\n');
}

function buildVisualNovelDirectorScriptContract(state, {
    backgroundKey = '',
    castIds = [],
    choices = [],
    includeStatePatch = false,
    mode = 'narrative',
} = {}) {
    const safeBackgroundKey = backgroundKey || preferredBackdropKeyForCurrentState(state) || state?.visuals?.sceneBackdrop?.currentKey || 'rain_bell';
    const safeCastIds = Array.isArray(castIds) ? castIds.filter(Boolean).slice(0, 6) : [];
    const safeChoices = Array.isArray(choices) ? choices.filter(Boolean).slice(0, VISUAL_NOVEL_VISIBLE_CHOICE_LIMIT) : [];
    const queueBrief = visualNovelQueueContinuationBrief(state);
    return [
        '【视觉小说导演台本合约】',
        `导演职责：你同时是小说作者、视觉小说导演和分镜师；先保证前后文小说连贯，再用结构化台本把地点、出场人物、语气、动作、表情和镜头交给本地舞台。mode=${mode}`,
        '可见正文：目标 240-560 个中文字符，超过 700 就应自行压缩，超过 820 等同失败。首个非空字符必须是中文小说正文，绝不能以 <、{、` 或“隐藏台本”开头；每轮只写一个可播放小节，不要把整场交涉/战斗/移动一次写完。输出前必须自检：任意连续 80 字或同一组台词不得在同一回复里出现两次，发现重复只保留第一次。隐藏台本 segments 目标 6-9 段，允许 4-12 段，超过 12 段失败，写完立刻追加隐藏台本；正文宁可短，也必须保证隐藏 JSON 完整闭合。旁白只负责镜头/环境/因果/危险感；角色台词必须是“角色名：「台词」”；先写玩家上一行动如何落地，再写 NPC/环境即时反应，再推进一个新线索、代价、关系变化、危险变化或伏笔回收。',
        '追问规则：如果玩家行动是在问“是谁、什么事、为什么、怎么做、具体条件、代价、地点、时间”，本轮必须给出一个新的可验证答案、明确拒绝理由或新的交换条件；不能连续用“没有立刻回答”“喝了一口”“你们有两个选择”“你们得替我做一件事”拖延同一个问题。',
        queueBrief,
        `素材使用：backgroundKey 必须从“本轮场景资产索引”选择，不准编造 key；建议=${safeBackgroundKey}。castIds 只写本镜头实际在场/发声/被镜头明确呈现的人，建议=${safeCastIds.join(',') || '按正文实际角色决定'}。动作/语气/表情/姿势字段会直接驱动立绘差分和 CG 候选。`,
        '候选行动：choices 必须是当前现场可执行动作，不是远处剧情菜单；每条至少绑定两个现场锚点：当前地点、在场人物、关键物件、线索、风险或目标；至少一半 choices 点名当前人物或地点；禁止把本轮玩家刚执行过的行动原样放回下一轮 choices，已执行动作必须转化为后续动作、代价应对、追问、撤离、观察新变化或策略调整。',
        '剧情导演字段：RE0_VN_SCRIPT.beat 必须是对象，不能写成字符串；progressDelta 必须是 beat.progressDelta 的短字符串数组，不能写到顶层，不能写对象数组、数字权重或 {"thread":...,"delta":...}。beat 说明本轮节拍 type/pacing/progressDelta/payoffLoopId/nextHook。progressDelta 写本轮真实推进了什么，例如 new_clue、relationship_shift、danger_shift、payoff、location_transition；没有推进就应缩小事件范围重写，不要输出空转台本。',
        '隐藏注释格式：只能在可见正文之后追加 <!-- RE0_VN_SCRIPT {...} -->，不要写成代码块，不要作为剧情展示；如果 token 紧张，优先保证隐藏 JSON 完整可解析。隐藏 JSON 必须能被 JSON.parse 直接解析：所有 key 使用英文双引号；所有 string value 内部禁止再出现英文双引号，必要时使用中文引号「」或直接省略引号；不要在隐藏注释 --> 后追加任何说明。',
        '隐藏台本长度：segments 不写 id，type 只能是 narration 或 dialogue；segments.text 每段 30-80 字，action 8-24 字，tone/expression/pose/camera/focus/sfx 只写短词；choices 必须是 3-6 条短字符串数组，每条 35-75 字，绝不能写成带 id、anchors、text 的对象数组。dialogue.text 只能写 speakerId 实际出口台词；旁白 narration 不能承载 NPC 第一人称供述；动作、神情、心理和转述摘要必须放进 action/expression/pose/tone。门外/隔门/巷口等未揭示声源说话时 speakerId 写 unknown_male 或 unknown_female，禁止挂到欧文/爱蜜莉雅/旁白。角色 ID 必须使用素材库 ID，例如菲鲁特只能写 felt，禁止写 rider/girl。',
        `JSON schema：{"version":"${VISUAL_NOVEL_SCRIPT_VERSION}","backgroundKey":"${safeBackgroundKey}","castIds":["角色id"],"scene":{"location":"地点","time":"时间","mood":"气氛"},"beat":{"type":"reveal/conflict/payoff/transition/daily/adult-intimacy/survival","pacing":"balanced/fast/climax/slow-burn","progressDelta":["new_clue","relationship_shift"],"payoffLoopId":"可选伏笔id","nextHook":"下一步可验证钩子"},"segments":[{"type":"narration","text":"镜头旁白","action":"环境/镜头动作","tone":"压抑/温柔/警惕","camera":"wide/close/over_shoulder","focus":"视觉焦点","sfx":"雨声/钟声"},{"type":"dialogue","speakerId":"emilia","text":"实际出口台词","action":"伸手/后退/递物/回避视线","tone":"犹豫/温柔/威胁","expression":"soft_smile/vulnerable/cold","pose":"hand_reach/book_hold/interrogate","camera":"close","focus":"手套/徽章/伞柄"}],"choices":["候选行动"]${includeStatePatch ? ',"statePatch":{"current":{"location":"最小地点同步"},"gameplay":{"activeObjective":"最小目标同步"}}' : ''}}`,
        safeChoices.length ? `候选行动参考：${safeChoices.join(' / ')}` : '',
        '本轮场景资产索引：',
        sceneAssetIndexForPrompt(state, 18),
        '本轮角色素材索引：',
        characterAssetIndexForPrompt(state, 12),
    ].filter(Boolean).join('\n');
}

function backdropSearchText(state) {
    const rumorText = (state.flags?.pendingRumors || [])
        .map((item) => typeof item === 'string' ? item : `${item.channel || ''} ${item.text || item.summary || ''}`)
        .join(' ');
    const revealText = (state.flags?.pendingReveals || [])
        .map((item) => typeof item === 'string' ? item : `${item.title || ''} ${item.summary || item.event || ''}`)
        .join(' ');
    const setup = state.settingLayers?.setupCanon || {};
    return [
        state.mode,
        state.current?.location,
        state.current?.time,
        state.visuals?.sceneBackdrop?.lastNarrativeText,
        state.answerBook?.active ? '答案之书 死亡 回归 魔女' : '',
        state.gameplay?.activeObjective,
        state.gameplay?.lastPlayerAction,
        state.gameplay?.lastOutcome,
        setup.birthplace,
        setup.initialScenario,
        rumorText,
        revealText,
        ...(state.gameplay?.openQuestions || []),
    ].filter(Boolean).join(' ');
}

