    stage.dataset.re0VnCustomActionDraft = vnRuntime.customActionDraft || '';
    stage.dataset.re0VnCastLimit = String(modeTemplate.castLimit);
    stage.dataset.re0VnCastIds = cast.map((profile) => profile.id).join(',');
    stage.dataset.re0VnSceneCastIds = sceneCastIds.join(',');
