    const visualBackdropState = state.visuals?.sceneBackdrop || {};
    const appliedBackdropKey = document.body?.dataset?.re0Backdrop || '';
    const debugLockedPreferredBackdropKey = Number(state.flags?.debugVnLockUntil || 0) > Date.now()
