            assetPlanBackdropConfidence: vnStage?.dataset?.re0VnAssetPlanBackdropConfidence || state.visuals?.visualNovel?.lastAssetPlan?.selectedBackdropConfidence || '',
            assetPlanCandidateKeys: (vnStage?.dataset?.re0VnAssetPlanCandidateKeys || '')
