function summarizeVisualNovelContract(state) {
    const vn = visualNovelRuntimeState(state);
    const roleMetrics = normalizeVisualNovelRoleMetrics(vn.roleMetrics, vn.segments);
    const stageConsistency = vn.lastStageConsistency || {};
    const segments = Array.isArray(vn.segments) ? vn.segments : [];
    const currentIndex = Math.max(0, Math.min(Math.max(0, segments.length - 1), Number(vn.currentIndex) || 0));
    const visibleWindow = segments.slice(Math.max(0, currentIndex - 2), Math.min(segments.length, currentIndex + 3));
    const segmentLine = segments.length
        ? visibleWindow.map((segment, index) => `${index + 1}.${segment.type === 'dialogue' ? segment.speakerName : '世界意志'}:${shortPromptText(segment.text, 36)}`).join(' / ')
        : '尚未解析本轮 VN segments';
    const castLine = Array.isArray(vn.castIds) && vn.castIds.length
        ? vn.castIds.map((id) => getProfile(id)?.name || id).slice(0, 8).join('、')
        : '由当前场景人物与正文提及角色决定';
    return `- 开关: ${vn.enabled === false ? '关闭' : '开启'} / script=${vn.scriptEnabled === false ? 'off' : 'on'} / source=${vn.scriptSource || 'none'} / index=${Number(vn.currentIndex || 0) + 1}/${vn.segments?.length || 0} / queue=${vn.queueMode || 'replace'} / trimmed=${vn.queueTrimmedCount || 0}
- 演出契约: ${shortPromptText(vn.contract || buildDefaultVisualNovelState().contract, 180)}
- 输出形态: 可见正文按 galgame 分镜推荐写成 6-9 个短演出段，允许 4-12 段，超过 12 段失败；首个非空字符必须是小说正文，不能以隐藏注释、JSON 或代码块开头；旁白只写镜头/环境/因果；角色台词用“角色名：「台词」”。模型每次回复会被本地解析并追加到 VN 舞台缓存队列尾部，点击/自动播放只消费已缓存队列；等待新回复时不得要求本地扩展伪造剧情。隐藏 RE0_VN_SCRIPT 必须使用 ${VISUAL_NOVEL_SCRIPT_VERSION}，dialogue.text 只写实际出口台词，segments 除 text 外优先补 action/tone/expression/pose/camera/focus/sfx，供舞台表演和素材差分匹配。backgroundKey 必须从本轮资产索引选择，castIds 只写本镜头实际在场/发声/被镜头明确呈现的角色。
${buildVisualNovelDirectorScriptContract(state, { mode: 'context-brief' })}
- 角色发声验收: ${roleMetrics.roleDrivenPass ? '通过' : '未达标'} / 直接发声 ${roleMetrics.directSpeakerCount} 人（${roleMetrics.directSpeakerNames.join('、') || '无'}）/ 对白 ${roleMetrics.dialogueSegments} 段 / 旁白占比 ${Math.round(roleMetrics.narratorShare * 100)}%。
- 当前解析: ${segmentLine}
- 舞台角色: ${castLine}
- 覆盖层: active=${visualNovelOpenModalName(vn)} / modalCount=${visualNovelOpenModalCount(vn)} / overlayCount=${visualNovelOpenOverlayCount(vn)} / worldStatus=${vn.worldStatusOpen === true ? 'open' : 'closed'} / UI-only 面板不得改写剧情事实。
- VN 安全补丁: ${shortPromptText(vn.lastStatePatchSummary || state.flags?.lastVnStatePatch || '无', 160)}
- VN 舞台一致性: ${shortPromptText(stageConsistency.summary || state.flags?.lastVnStageConsistency || '等待校验', 150)}
- VN 队列续写: ${shortPromptText(visualNovelQueueContinuationBrief(state), 260)}
- 解析警告: ${(vn.parseWarnings || []).slice(-3).join(' / ') || '无'}`;
}

function recordSidecarOutput(state, { type = 'note', title = '辅助输出', content = '', source = 'extension' } = {}) {
    if (!state?.visuals || !content) {
        return null;
    }
    const limit = sidecarContentLimit(type, source);
    const entry = {
        id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        type,
        title,
        content: clampMultilineText(content, limit),
        source,
        day: state.current?.day || 1,
        time: state.current?.time || '',
        location: state.current?.location || '',
        createdAt: new Date().toISOString(),
    };
    state.visuals.sidecarHistory = [...(state.visuals.sidecarHistory || []), entry].slice(-12);
    state.visuals.lastSidecarTitle = entry.title;
    state.visuals.lastSidecarAt = entry.createdAt;
    if (type === 'visual') {
        state.visuals.lastPrompt = shortPromptText(entry.content, 420);
        state.visuals.promptHistory = [...(state.visuals.promptHistory || []), shortPromptText(entry.content, 520)].slice(-8);
    }
    return entry;
}

function latestSidecarOutput(state) {
    const history = state?.visuals?.sidecarHistory;
    return Array.isArray(history) && history.length ? history[history.length - 1] : null;
}

function formatVisualSidecarFromJson(data, state) {
    const fallbackTitle = `第${state.current?.day || 1}日${state.current?.time || ''} · ${state.current?.location || '当前场景'} 插图提示词`;
    if (data?.chinesePrompt && typeof data.chinesePrompt === 'string' && data.chinesePrompt.trim().startsWith('{')) {
        try {
            data = { ...data, ...extractJson(data.chinesePrompt) };
        } catch {
            // Keep the original payload; the caller still gets a usable fallback.
        }
    }
    if (!data || typeof data !== 'object') {
        return '';
    }
    const parts = [
        `【标题】${data.title || fallbackTitle}`,
        `【中文提示词】${data.chinesePrompt || data.zh || ''}`,
        `【English prompt】${data.englishPrompt || data.en || ''}`,
        `【Negative prompt】${data.negativePrompt || 'low quality, blurry, bad anatomy, extra fingers, watermark, text, logo, minor, child, loli, explicit sex, nude, genitalia, sexual violence, non-consensual'}`,
        `【建议画幅】${data.aspectRatio || data.aspect || '16:9 或 3:4'}`,
    ];
    if (data.adultPrompt) {
        parts.splice(3, 0, `【成人氛围版提示词】${data.adultPrompt}`);
    }
    if (data.insertNote) {
        parts.push(`【插入剧情】${data.insertNote}`);
    }
    return parts.filter((line) => !/】\s*$/.test(line)).join('\n');
}

