function adultSceneSignalsFromText(text, state) {
    if (!state?.adultContent?.enabled) {
        return [];
    }
    const source = cleanMessageText(text || '', 2200);
    if (!source) {
        return [];
    }
    const signals = [];
    const checks = [
        ['slow_burn', /(暧昧|脸红|避开视线|目光|靠近|气息|呼吸|独处|灯下|雨声|沉默|心跳|手指|肩|锁骨|腰线|衣料|热度|吻|拥抱|贴近)/],
        ['pure_love', /(温柔|信任|告白|守护|照料|并肩|依靠|握住|披上|包扎|承诺|回家|不想失去)/],
        ['women_love', /(百合|女性之间|她看着她|她靠近她|两个女人|女孩子之间|少女之间)/],
        ['triangle', /(三角|嫉妒|吃醋|修罗场|另一个人|选择谁|夹在.*之间|目光越过你|她看向.*而不是你)/],
        ['betrayal_jealousy', /(背叛|误会|占有|嫉妒|夺走|不该看见|别碰|属于|NTR|裂缝|动摇|怀疑你)/i],
        ['consensual_power_exchange', /(主从|命令|跪|臣服|服从|奖励|惩罚|支配|被允许|许可|合意|交换条件)/],
        ['tragic_romance', /(虐恋|悲恋|相爱|不能在一起|立场|罪责|牺牲|死后|来不及|救不了|再次失去)/],
        ['dangerous_attraction', /(危险吸引|猎物|猎人|敌对|杀意|刀尖|威胁|靠近.*危险|不该心动|禁忌)/],
        ['dark_horror_romance', /(猎奇|伤痕|血雨|阴影|恐怖|魔女|创伤|噩梦|余韵|危险感|R18G)/i],
        ['aftercare', /(事后|余温|披衣|洗去|擦拭|清理伤口|热水|照料|发抖|疲惫|靠在|睡着)/],
    ];
    for (const [tag, pattern] of checks) {
        if (pattern.test(source)) {
            signals.push(tag);
        }
    }
    const profiles = mentionedProfilesForCardSync(source, '', 6);
    const highDesire = profiles.some((profile) => {
        const card = characterCardForProfile(state, profile);
        const metrics = adultMetricsForProfile(state, profile, card);
        return Number(metrics.desire || 0) >= 45 || Number(metrics.affection || 0) >= 55;
    });
    if (highDesire && /(独处|靠近|视线|沉默|夜|房间|雨|火光|酒|床|门关上|呼吸)/.test(source)) {
        signals.push('slow_burn');
    }
    const palette = adultPalette(state);
    return [...new Set(signals)]
        .filter((tag) => adultRelationshipTagCatalog[tag])
        .filter((tag) => palette.enabledTags.includes(tag) && !palette.disabledTags.includes(tag) && !palette.hardLimits.includes(tag));
}

function adultPromptToneFromPalette(palette) {
    if (palette.promptIntensity === 'bold-suggestive') {
        return '大胆但不露骨：镜头可以贴近成年角色的衣料褶皱、肩颈锁骨、压低的呼吸、手指停顿、眼神占有欲、危险距离和心理张力；用光影与姿势让读者联想，不描写露骨性行为。';
    }
    if (palette.promptIntensity === 'restrained') {
        return '克制暧昧：用眼神、沉默、衣角、手背、雨声和烛火暗示关系升温，不直接展示亲密过程。';
    }
    return '电影感软性成人：强调成熟暧昧、情绪热度、身体距离、权力关系、衣料与光影，性感但非露骨。';
}

