function maybeRecordAdultSceneSidecar(state, assistantText, messageId) {
    if (!state?.adultContent?.enabled || state.flags?.lastAdultSceneSidecarMessageId === messageId) {
        return false;
    }
    const content = buildAdultSceneSidecar(state, assistantText);
    if (!content) {
        return false;
    }
    recordSidecarOutput(state, {
        type: 'visual',
        title: '成人场景提示词',
        content,
        source: 'adult-scene-auto',
    });
    state.flags ??= {};
    state.flags.lastAdultSceneSidecarMessageId = messageId;
    return true;
}

function compactStateForVisualSidecar(state) {
    const presence = inferPresence(state);
    const gameplay = state.gameplay || buildDefaultGameplayState();
    const backdrop = selectSceneBackdrop(state);
    return {
        mode: state.mode,
        current: {
            day: state.current?.day || 1,
            time: state.current?.time || '',
            location: state.current?.location || '',
            viewpoint: state.current?.viewpoint || '',
        },
        adultContent: {
            enabled: !!state.adultContent?.enabled,
            mode: state.adultContent?.mode || 'off',
            adultOnlyWorld: !!state.adultContent?.adultOnlyWorld,
        },
        sceneCharacters: presence.sceneCharacters.slice(0, 6),
        areaCharacters: presence.areaCharacters.slice(0, 8),
        gameplay: {
            activeObjective: shortPromptText(gameplay.activeObjective || '', 160),
            objectiveStage: shortPromptText(gameplay.objectiveStage || '', 80),
            tension: gameplay.tension ?? 0,
            openQuestions: (gameplay.openQuestions || []).slice(-4).map((item) => shortPromptText(item, 120)),
            actionHints: (gameplay.actionHints || []).slice(-3).map((item) => shortPromptText(item, 100)),
            lastPlayerAction: shortPromptText(gameplay.lastPlayerAction || '', 120),
            lastOutcome: shortPromptText(gameplay.lastOutcome || '', 160),
        },
        discoveredClues: (state.discoveredClues || []).slice(-5).map((item) => shortPromptText(item, 120)),
        tonePacing: {
            currentBeat: state.tonePacing?.currentBeat || 'daily-adventure',
            reliefDebt: state.tonePacing?.reliefDebt ?? 0,
        },
        backdrop: {
            key: backdrop.key,
            title: backdrop.title,
            summary: backdrop.summary,
            prompt: shortPromptText(backdrop.prompt, 260),
        },
    };
}

async function generateVisualSidecar(state, reason = 'manual') {
    try {
        setHudStatus('正在生成插图提示词辅助输出...');
        const response = await fetch('/api/re0-sim/visual-prompt', {
            method: 'POST',
            headers: getRequestHeaders(),
            body: JSON.stringify({
                model: 'mimo-v2.5-pro',
                state: compactStateForVisualSidecar(state),
                sceneCharacters: inferPresence(state).sceneCharacters,
            }),
        });
        const json = await response.json().catch(() => ({}));
        if (!response.ok) {
            throw new Error(json?.error || `HTTP ${response.status}`);
        }
        const content = formatVisualSidecarFromJson(json.prompt, state);
        if (!content) {
            throw new Error('插图提示词为空');
        }
        const entry = recordSidecarOutput(state, {
            type: 'visual',
            title: `插图提示词 · ${state.current?.location || '当前场景'}`,
            content,
            source: reason,
        });
        state.flags ??= {};
        state.flags.visualSidecarRequested = false;
        state.flags.systemNotice = '';
        saveState();
        refreshStatePrompt();
        renderHud();
        setHudStatus('插图提示词已放入辅助输出面板');
        return entry;
    } catch (error) {
        console.error('[Re0 Adventure Engine] Visual sidecar generation failed.', error);
        setHudStatus(`插图提示词失败：${error.message}`);
        throw error;
    }
}

function extractAuxiliarySidecarsFromText(text) {
    const lines = String(text || '').split('\n');
    const sidecarStart = lines.findIndex((line) => /(?:【\s*)?(插图提示词|生图提示词|图像提示词|成人场景提示词|成人氛围版提示词|成人氛围生图提示词|English prompt|Negative prompt|负面提示词|建议画幅|幕后补充|后台补充|角色状态补充)(?:\s*】)?/i.test(line));
    if (sidecarStart < 0) {
        return { cleaned: String(text || ''), sidecars: [] };
    }
    const cleaned = lines.slice(0, sidecarStart).join('\n').trim();
    const content = lines.slice(sidecarStart).join('\n').trim();
    const isVisual = /(插图|生图|图像|prompt|画幅|负面)/i.test(content);
    return {
        cleaned,
        sidecars: [{
            type: isVisual ? 'visual' : 'note',
            title: isVisual ? '插图提示词辅助输出' : '辅助补充',
            content,
            source: 'assistant-message',
        }],
    };
}

const PAGE_COUNTER_LINE_RE = /^\s*1(?:\s|\u200B|\u200C|\u200D|\uFEFF)*[/／](?:\s|\u200B|\u200C|\u200D|\uFEFF)*1\s*$/u;
const PAGE_COUNTER_TAIL_RE = /\n?\s*1(?:\s|\u200B|\u200C|\u200D|\uFEFF)*[/／](?:\s|\u200B|\u200C|\u200D|\uFEFF)*1\s*$/u;
const PAGE_COUNTER_ANY_RE = /1(?:\s|\u200B|\u200C|\u200D|\uFEFF)*[/／](?:\s|\u200B|\u200C|\u200D|\uFEFF)*1/u;

function stripInlineUiStatusFromReply(text) {
    const lines = String(text || '').split('\n');
    const cleaned = [];
    let skippingStatusBlock = false;
    for (const line of lines) {
        const cleanedLine = stripGeneratedActionDirectiveInlineSuffix(line);
        const trimmed = cleanedLine.trim();
        if (!trimmed) {
            continue;
        }
        const plain = trimmed.replace(/^[*_~`]+|[*_~`]+$/g, '').trim();
        const isActionHeader = /^(?:【\s*)?下一步可调查\s*\/\s*可行动方向(?:\s*】)?/u.test(trimmed);
        if (isActionHeader) {
            skippingStatusBlock = false;
            cleaned.push(cleanedLine);
            continue;
        }
        if (isGeneratedActionDirectiveLine(cleanedLine)) {
            continue;
        }
        const isStandaloneStatusLine = /^【?\s*(锚点|循环|死亡次数|魔女气味|新死亡锚点|不可逆代价|已验证边界|新信息|掌心字迹|资源|压力|证据|世界线偏移|主线钟|后台日|核心教训|脚底裂痕|新增异常|已带回策略|新增警告)\s*[：:]/u.test(plain)
            || /^【[^】]*(?:死亡.*核心教训|核心教训|脚底裂痕|新增异常|已带回策略|新增警告)[^】]*】$/u.test(plain)
            || PAGE_COUNTER_LINE_RE.test(plain);
        if (isStandaloneStatusLine) {
            continue;
        }
        const startsUiStatusBlock = /^(?:【\s*)?(状态|当前状态|HUD|系统|主线(?:模式|钟|通知)?|世界线|角色同步|成人侧栏|成人场景提示词|成人氛围版提示词|插图提示词|生图提示词|辅助输出|后台切片报告|角色状态补充|核心教训|脚底裂痕|新增异常|已带回策略|新增警告)(?:\s*[·:：/].*)?(?:\s*】)?/u.test(plain)
            || /^【?\s*主线模式\s*[·:：/]\s*主线钟推进\s*】?/u.test(plain);
        if (startsUiStatusBlock) {
            skippingStatusBlock = true;
            continue;
        }
        if (skippingStatusBlock) {
            continue;
        }
        const isInlineUiLine = /^(?:[-•]\s*)?(?:主线钟|主线通知|偏移率|世界线偏移|证据|压力|钱|食物|人情|资源|目标达成|好感|情感值|角色同步|显影队列|后台日|模式)\s*[:：+]|^(?:[-•]\s*)?(?:证据|压力|钱|食物|人情)\s*[+-]\d+/u.test(trimmed);
        if (isInlineUiLine) {
            continue;
        }
        cleaned.push(cleanedLine);
    }
    return cleaned.join('\n')
        .replace(/(?:^|\s)锚点\s*[：:][^。！？\n]{0,180}(?:。|$)/gu, ' ')
        .replace(/(?:^|\s)(?:死亡次数|魔女气味|新死亡锚点|不可逆代价|已验证边界|新增异常|已带回策略|新增警告|核心教训|脚底裂痕)\s*[：:][^。！？\n]{0,180}(?:。|$)/gu, ' ')
        .replace(/带回线索\s*[：:]/gu, '你记住了：')
        .replace(/行动方针修正\s*[：:]/gu, '这一次首先要改变的是：')
        .replace(/不可原样重复\s*[：:]/gu, '你在心里划掉了上一轮的窄路：')
        .replace(PAGE_COUNTER_TAIL_RE, '')
        .replace(/\n{3,}/g, '\n\n')
        .replace(/[ \t]{2,}/g, ' ')
        .trim();
}

function sanitizeVisibleNarrativeMetaText(text = '') {
    const raw = String(text || '');
    const marker = raw.match(/<!--\s*RE0_VN_SCRIPT[\s\S]*?-->/iu);
    const sanitizeVisible = (visible) => String(visible || '')
        .replace(/罗兹瓦尔的剧本|罗兹瓦尔剧本/gu, '罗兹瓦尔的布局')
        .replace(/福音书剧本/gu, '福音书布局')
        .replace(/剧本/gu, '布局')
        .replace(/原作的齿轮/gu, '命运的齿轮')
        .replace(/原作线/gu, '既定因果')
        .replace(/原作剧情/gu, '既定因果')
        .replace(/原作/gu, '命运')
        .replace(/\bRAG\b/giu, '记忆索引')
        .replace(/路线锁定/gu, '无形牵引')
        .replace(/玩家选择/gu, '刚才的决定')
        .replace(/系统提示/gu, '直觉警讯')
        .replace(/游戏机制/gu, '世界规则')
        .replace(/不能直接说出[“"「]?死亡回归[”"」]?/gu, '不能把那种违和的直觉说得太明白')
        .replace(/不说出[“"「]?死亡回归[”"」]?/gu, '不把那种违和的直觉说出口')
        .replace(/经历过[“"「]?死亡回归[”"」]?/gu, '见过这条路的尽头')
        .replace(/死亡回归/gu, '不可言说的既视感')
        .replace(/上一次循环|上一轮循环/gu, '那道残留的直觉')
        .replace(/我死过/gu, '我见过这条路的尽头')
        .replace(/大模型|模型输出/gu, '世界意志');
    if (!marker) {
        return sanitizeVisible(raw);
    }
    const before = raw.slice(0, marker.index);
    const afterStart = Number(marker.index || 0) + marker[0].length;
    const after = raw.slice(afterStart);
    return `${sanitizeVisible(before).trimEnd()}\n${marker[0]}${after}`;
}

function hasInlineUiStatusText(text) {
    return /(?:^|[\n【\s])(锚点|主线模式|主线钟|当前状态|死亡次数|魔女气味|新死亡锚点|不可逆代价|已验证边界|新增异常|已带回策略|新增警告|HUD|世界线偏移|角色同步|成人侧栏|后台日)\s*[：:]|【[^】]*(?:核心教训|脚底裂痕|新增异常|已带回策略|新增警告)[^】]*】/u.test(String(text || ''))
        || /(?:^|[\n\s])(换方针|避免重演|追查异常|时间控制|如果现场线索|观察\s+[^。！？!?]{1,80}?对你|观察谁会|先用一个小预警|可以输入“推进时间”|想看后台变化)(?:\s|[：:，,。])?/u.test(String(text || ''))
        || PAGE_COUNTER_ANY_RE.test(String(text || ''));
}

function setChatMessageText(message, text) {
    if (!message) {
        return;
    }
    message.mes = text;
    if ('message' in message) {
        message.message = text;
    }
    if (message.extra && typeof message.extra === 'object' && 'display_text' in message.extra) {
        message.extra.display_text = text;
    }
}

function cleanCharacterCardMemoryText(text, limit = 360) {
    let source = stripInlineUiStatusFromReply(String(text || ''));
    source = source
        .replace(/\[\/?Re0 Adventure Engine State[^\]]*\]/gi, ' ')
        .replace(/\b(?:AUTHORITATIVE|Re0 Adventure Engine State)\b[\s\S]{0,220}?(?=(第\d+日|$))/gi, ' ')
        .replace(/\b\w{0,10}\s*State\s*-\s*/gi, ' ')
        .replace(/(?:死亡次数|命运锚点|魔女气味|已知线索|主线钟|世界线偏移|HUD|状态字段)\s*[:：][^。！？\n]{0,160}/g, ' ')
        .replace(/【[^】]*(?:死亡次数|魔女气味|主线模式|主线钟|状态|HUD|系统|资源|证据|压力|角色同步)[^】]*】/g, ' ');
    return cleanPanelText(source, limit);
}

function extractAndStoreAuxiliaryOutputs(state, context, messageId) {
    const message = context.chat?.[messageId];
    if (!message || message.is_user) {
        return String(message?.mes ?? message?.message ?? '');
    }
    const raw = String(message.extra?.display_text ?? message.mes ?? message.message ?? '');
    const { cleaned, sidecars } = extractAuxiliarySidecarsFromText(raw);
    const narrativeOnly = stripInlineUiStatusFromReply(sidecars.length ? cleaned : raw);
    if (!sidecars.length) {
        if (narrativeOnly !== raw.trim()) {
            setChatMessageText(message, narrativeOnly);
            updateMessageBlock(messageId, message);
            state.flags ??= {};
            state.flags.lastUiStatusStrippedMessageId = messageId;
            return narrativeOnly;
        }
        return raw;
    }
    for (const sidecar of sidecars) {
        recordSidecarOutput(state, sidecar);
    }
    const replacement = narrativeOnly || '';
    setChatMessageText(message, replacement);
    updateMessageBlock(messageId, message);
    state.flags ??= {};
    state.flags.lastSidecarMessageId = messageId;
    return replacement;
}

function summarizeSettingLayers(state) {
    const layers = state.settingLayers || buildDefaultSettingLayers();
    if (state.mode !== 'setting_edit') {
        const canon = layers.setupCanon;
        const setupCanon = canon ? [
            `- 建档同步: ${canon.protagonistName || '无名异乡人'} / ${shortPromptText(canon.birthplace || '', 34)} / ${shortPromptText(canon.firstNpc || '', 34)}`,
            `- 主角底盘: ${shortPromptText(canon.appearance || '', 40)}；${shortPromptText(canon.personality || '', 40)}；${shortPromptText(canon.ability || '', 48)}`,
            `- 初始剧情: ${shortPromptText(canon.initialScenario || '', 70)}；混沌=${shortPromptText(canon.chaosLevel || '', 34)}`,
        ].join('\n') : '- 建档同步: 尚未锁定';
        const saveEdits = (layers.saveEdits || []).slice(-3)
            .map((edit) => `- [${edit.id}] ${edit.target}: ${shortPromptText(edit.instruction, 80)}`)
            .join('\n') || '- 无';
        const globalEdits = getGlobalSettingEdits().slice(-3)
            .map((edit) => `- [${edit.id}] ${edit.target}: ${shortPromptText(edit.instruction, 80)}`)
            .join('\n') || '- 无';
        return `- 设定按时间/空间分层；只有用户声明“我是用户，我现在要跳出故事，修改剧情设定”才进入编辑。
- 默认修改范围: ${layers.editPolicy?.defaultScope || 'save'}；全局有效必须显式声明。
- 建档全局同步:
${setupCanon}
- 存档级修改:
${saveEdits}
- 全局级修改:
${globalEdits}`;
    }
    const temporal = Object.entries(layers.temporal || {})
        .map(([key, layer]) => `- ${key} / ${layer.label}: ${layer.horizon}；${layer.description}`)
        .join('\n') || '- 未配置时间层';
    const spatial = Object.entries(layers.spatial || {})
        .map(([key, layer]) => `- ${key} / ${layer.label}: ${layer.range}；${layer.description}`)
        .join('\n') || '- 未配置空间层';
    const saveEdits = (layers.saveEdits || []).slice(-12)
        .map((edit) => `- [${edit.id}] ${edit.target}: ${edit.instruction}`)
        .join('\n') || '- 当前存档暂无设定修改';
    const globalEdits = getGlobalSettingEdits().slice(-12)
        .map((edit) => `- [${edit.id}] ${edit.target}: ${edit.instruction}`)
        .join('\n') || '- 暂无全局设定修改';
    return `- 设定教义: ${layers.doctrine || buildDefaultSettingLayers().doctrine}
- 触发方式: ${layers.editPolicy?.trigger || buildDefaultSettingLayers().editPolicy.trigger}
- 默认作用范围: ${layers.editPolicy?.defaultScope || 'save'}（未声明时仅本次存档有效）
- 时间层:
${temporal}
- 空间层:
${spatial}
- 当前存档级修改:
${saveEdits}
- 全局级修改:
${globalEdits}`;
}

