function summarizePromptSectionCoverage(compactPrompt) {
    const text = String(compactPrompt || '');
    const countPresent = (sections) => sections.filter((section) => text.includes(section));
    const core = countPresent(promptCoreSections);
    const support = countPresent(promptSupportSections);
    const missingCore = promptCoreSections.filter((section) => !text.includes(section));
    const missingSupport = promptSupportSections.filter((section) => !text.includes(section));
    return [
        `核心 ${core.length}/${promptCoreSections.length}`,
        `扩展 ${support.length}/${promptSupportSections.length}`,
        missingCore.length ? `缺核心:${missingCore.slice(0, 2).map((item) => item.replace(/：$/, '')).join('/')}` : '核心完整',
        missingSupport.length ? `缺扩展:${missingSupport.slice(0, 3).map((item) => item.replace(/：$/, '').slice(0, 10)).join('/')}` : '扩展完整',
    ].join(' · ');
}

function buildPromptCompressionDiagnostics(rawPrompt, compactPrompt, state = null) {
    const raw = String(rawPrompt || '');
    const compact = String(compactPrompt || '');
    const rawSections = splitPromptIntoSections(raw);
    const compactSections = splitPromptIntoSections(compact);
    const maxChars = Number(extension_settings[MODULE_NAME]?.statePromptMaxChars) || defaultSettings.statePromptMaxChars;
    const sections = promptCompressionHeaders
        .filter((header) => rawSections.has(header))
        .map((header) => {
            const rawText = rawSections.get(header) || '';
            const compactText = compactSections.get(header) || '';
            const relevance = promptSectionRelevance(header, state);
            const status = !compactText
                ? 'dropped'
                : compactText.length < rawText.length * 0.72
                    ? 'compressed'
                    : 'kept';
            const reason = status === 'dropped'
                ? `notInjected: budget=${maxChars}, relevance=${relevance}, sectionChars=${rawText.length}`
                : status === 'compressed'
                    ? `compressed: ${rawText.length}->${compactText.length}, relevance=${relevance}`
                    : `kept: ${compactText.length} chars, relevance=${relevance}`;
            return {
                header: header.replace(/：$/, ''),
                rawChars: rawText.length,
                injectedChars: compactText.length,
                relevance,
                status,
                notInjectedReason: status === 'dropped' ? reason : '',
                reason,
            };
        });
    return {
        rawChars: raw.length,
        injectedChars: compact.length,
        maxChars,
        compressed: raw.length > compact.length,
        keptCount: sections.filter((item) => item.status === 'kept').length,
        compressedCount: sections.filter((item) => item.status === 'compressed').length,
        droppedCount: sections.filter((item) => item.status === 'dropped').length,
        droppedHeaders: sections.filter((item) => item.status === 'dropped').map((item) => item.header).slice(0, 10),
        sections: sections.slice(0, 48),
        generatedAt: new Date().toISOString(),
    };
}

function splitPromptIntoSections(prompt) {
    const text = String(prompt || '');
    const markers = promptCompressionHeaders
        .map((header) => {
            const index = text.indexOf(header);
            return index >= 0 ? { header, index } : null;
        })
        .filter(Boolean)
        .sort((a, b) => a.index - b.index);
    const sections = new Map();
    const preambleEnd = markers[0]?.index ?? text.length;
    sections.set('__preamble__', text.slice(0, preambleEnd).trim());
    markers.forEach((marker, index) => {
        const next = markers[index + 1]?.index ?? text.length;
        sections.set(marker.header, text.slice(marker.index, next).trim());
    });
    return sections;
}

function compactPromptSection(section, limit) {
    const text = String(section || '').trim();
    if (!text || text.length <= limit) {
        return text;
    }
    const lines = text.split('\n');
    const header = lines.shift() || '';
    const body = lines.join('\n').trim();
    return `${header}\n${clampMultilineText(body, Math.max(80, limit - header.length - 1), '\n...[本段已压缩，完整数据仍在本地 state/世界书/角色卡中]')}`;
}

function compactRulesSection(section, limit = 1600) {
    const text = String(section || '').trim();
    if (!text || text.length <= limit) {
        return text;
    }
    const keepPattern = /^(运行规则：|0\.|1\.|1b\.|1c\.|1d\.|1e\.|2\.|2b\.|3\.|6\.|7\.|7b\.|10\.|12\.|13\.|13b\.|13c\.|13d\.|13e\.|13f\.|15\.|17\.|18\.|19\.|20\.|21\.|22\.|23\.)/u;
    const lines = text
        .split('\n')
        .map((line) => line.trim())
        .filter((line) => keepPattern.test(line))
        .map((line) => shortPromptText(line, line.startsWith('3.') ? 360 : 260));
    const compact = [
        '运行规则：',
        '[规则段已结构化压缩：完整规则保存在扩展源码；以下为本轮必需约束]',
        ...lines.filter((line) => line && line !== '运行规则：'),
    ].join('\n');
    return compactPromptSection(compact, limit);
}

